import type { AccountEntity, FrostAppState } from "@rialo/frost-core";
import { useStore } from "@tanstack/react-store";
import { useFrostConfig } from "../context";

/**
 * Selector for the active account.
 * Defined at module level since it has no dependencies and never changes,
 * preventing unnecessary re-subscriptions in TanStack Store.
 */
const selectActiveAccount = (state: FrostAppState): AccountEntity | null => {
  if (!state.accountAddress) return null;
  return state.accounts.get(state.accountAddress) ?? null;
};

/**
 * Hook to get the currently active account.
 *
 * @returns Active account or null if not connected
 *
 * @example
 * ```tsx
 * function AccountInfo() {
 *   const account = useActiveAccount();
 *
 *   if (!account) return <div>Not connected</div>;
 *   return <div>Address: {account.address}</div>;
 * }
 * ```
 */
export function useActiveAccount(): AccountEntity | null {
  const config = useFrostConfig();
  return useStore(config.store, selectActiveAccount);
}
