/** biome-ignore-all lint/nursery/useExplicitType: <mouse events> */
import type { CSSProperties, ReactNode } from "react";
import { useCallback, useEffect, useRef, useState } from "react";
import { useActiveAccount } from "../hooks/useActiveAccount";
import { useActiveWallet } from "../hooks/useActiveWallet";
import { useConnectionStatus } from "../hooks/useConnectionStatus";
import { useDisconnectWallet } from "../hooks/useConnectWallet";
import { ChevronIcon, CopyIcon, DisconnectIcon } from "./icons";
import { WalletModal } from "./WalletModal";

export interface ConnectButtonProps {
  /** Label shown when disconnected */
  label?: string;
  /** Label shown while connecting */
  connectingLabel?: string;
  /** Label or formatter for connected state */
  connectedLabel?: string | ((address: string, walletName: string) => string);
  /** Callback when wallet successfully connects */
  onConnect?: (walletName: string, address: string) => void;
  /** Callback when wallet disconnects */
  onDisconnect?: () => void;
  /** Callback when connection fails */
  onError?: (error: Error) => void;
  /** Additional class name for the button */
  className?: string;
  /** Additional styles for the button */
  style?: CSSProperties;
  /** Whether the button is disabled */
  disabled?: boolean;
  /** Title for the wallet selection modal */
  modalTitle?: string;
  /** Whether to show the connected dropdown menu @default true */
  showDropdown?: boolean;
  /** Additional class for the dropdown menu */
  dropdownClassName?: string;
}

const defaultStyles: Record<string, CSSProperties> = {
  container: {
    position: "relative",
    display: "inline-block",
  },
  button: {
    display: "inline-flex",
    alignItems: "center",
    justifyContent: "center",
    gap: "0.5rem",
    padding: "0.625rem 1rem",
    fontSize: "0.9375rem",
    fontWeight: 500,
    color: "var(--frost-button-text, #ffffff)",
    backgroundColor: "var(--frost-primary, #3b82f6)",
    border: "none",
    borderRadius: "var(--frost-border-radius, 8px)",
    cursor: "pointer",
    transition: "all 0.15s ease",
    minWidth: "140px",
    fontFamily: "inherit",
  },
  buttonDisabled: {
    opacity: 0.6,
    cursor: "not-allowed",
  },
  buttonConnected: {
    backgroundColor: "var(--frost-button-connected-bg, #f3f4f6)",
    color: "var(--frost-button-connected-text, #111827)",
  },
  walletIcon: {
    width: 20,
    height: 20,
    borderRadius: 4,
    objectFit: "contain",
  },
  dropdown: {
    position: "absolute",
    top: "calc(100% + 4px)",
    right: 0,
    minWidth: "100%",
    backgroundColor: "var(--frost-dropdown-bg, #ffffff)",
    borderRadius: "var(--frost-border-radius, 8px)",
    boxShadow: "var(--frost-shadow, 0 4px 16px rgba(0, 0, 0, 0.12))",
    border: "1px solid var(--frost-border-color, #e5e7eb)",
    overflow: "hidden",
    zIndex: "var(--frost-z-index, 9999)" as unknown as number,
  },
  dropdownItem: {
    display: "flex",
    alignItems: "center",
    gap: "0.5rem",
    width: "100%",
    padding: "0.75rem 1rem",
    fontSize: "0.875rem",
    color: "var(--frost-text-color, #111827)",
    backgroundColor: "transparent",
    border: "none",
    cursor: "pointer",
    textAlign: "left",
    fontFamily: "inherit",
    transition: "background-color 0.15s ease",
  },
  dropdownDivider: {
    height: 1,
    backgroundColor: "var(--frost-border-color, #e5e7eb)",
    margin: 0,
  },
  addressDisplay: {
    padding: "0.75rem 1rem",
    fontSize: "0.75rem",
    color: "var(--frost-text-secondary, #6b7280)",
    fontFamily: "monospace",
    wordBreak: "break-all",
  },
  spinner: {
    width: 16,
    height: 16,
    border: "2px solid rgba(255, 255, 255, 0.3)",
    borderTopColor: "#ffffff",
    borderRadius: "50%",
    animation: "frost-spin 0.8s linear infinite",
  },
};

function truncateAddress(address: string, startChars: number = 6, endChars: number = 4): string {
  if (address.length <= startChars + endChars) return address;
  return `${address.slice(0, startChars)}...${address.slice(-endChars)}`;
}

export function ConnectButton({
  label = "Connect Wallet",
  connectingLabel = "Connecting...",
  connectedLabel,
  onConnect,
  onDisconnect,
  onError,
  className,
  style,
  disabled = false,
  modalTitle,
  showDropdown = true,
  dropdownClassName,
}: ConnectButtonProps): ReactNode {
  const [modalOpen, setModalOpen] = useState(false);
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [copied, setCopied] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);
  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const status = useConnectionStatus();
  const account = useActiveAccount();
  const wallet = useActiveWallet();

  const { mutate: disconnect } = useDisconnectWallet({
    onSuccess: () => {
      setDropdownOpen(false);
      onDisconnect?.();
    },
  });

  const isConnected = status === "connected" && account;
  const isConnecting = status === "connecting" || status === "reconnecting";

  // Use refs to avoid circular dependencies in useCallback
  const handlersRef = useRef<{
    clickOutside: (e: globalThis.MouseEvent) => void;
    escape: (e: globalThis.KeyboardEvent) => void;
  } | null>(null);

  const removeListeners = useCallback(() => {
    if (handlersRef.current) {
      document.removeEventListener("mousedown", handlersRef.current.clickOutside);
      document.removeEventListener("keydown", handlersRef.current.escape);
    }
  }, []);

  const addListeners = useCallback(() => {
    if (handlersRef.current) {
      document.addEventListener("mousedown", handlersRef.current.clickOutside);
      document.addEventListener("keydown", handlersRef.current.escape);
    }
  }, []);

  // Initialize handlers once
  if (!handlersRef.current) {
    handlersRef.current = {
      clickOutside: (e: globalThis.MouseEvent) => {
        if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
          setDropdownOpen(false);
          removeListeners();
        }
      },
      escape: (e: globalThis.KeyboardEvent) => {
        if (e.key === "Escape") {
          setDropdownOpen(false);
          removeListeners();
        }
      },
    };
  }

  const setDropdownOpenWithListeners = useCallback(
    (open: boolean) => {
      setDropdownOpen(open);
      if (open) {
        addListeners();
      } else {
        removeListeners();
      }
    },
    [addListeners, removeListeners]
  );

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      removeListeners();
      if (copyTimeoutRef.current) {
        clearTimeout(copyTimeoutRef.current);
      }
    };
  }, [removeListeners]);

  const handleButtonClick = useCallback(() => {
    if (isConnected) {
      if (showDropdown) {
        setDropdownOpenWithListeners(!dropdownOpen);
      } else {
        disconnect();
      }
    } else if (!isConnecting) {
      setModalOpen(true);
    }
  }, [
    isConnected,
    isConnecting,
    showDropdown,
    disconnect,
    setDropdownOpenWithListeners,
    dropdownOpen,
  ]);

  const handleCopyAddress = useCallback(async () => {
    if (!account?.address) return;
    try {
      await navigator.clipboard.writeText(account.address);
      setCopied(true);
      if (copyTimeoutRef.current) {
        clearTimeout(copyTimeoutRef.current);
      }
      copyTimeoutRef.current = setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error("Failed to copy address:", err);
    }
  }, [account?.address]);

  const handleModalConnect = useCallback(
    (walletName: string, address: string) => {
      setModalOpen(false);
      onConnect?.(walletName, address);
    },
    [onConnect]
  );

  const getButtonLabel = (): string => {
    if (isConnecting) return connectingLabel;
    if (isConnected && account) {
      if (typeof connectedLabel === "function") {
        return connectedLabel(account.address, wallet?.name ?? "");
      }
      if (typeof connectedLabel === "string") return connectedLabel;
      return truncateAddress(account.address);
    }
    return label;
  };

  const buttonStyles: CSSProperties = {
    ...defaultStyles.button,
    ...(isConnected ? defaultStyles.buttonConnected : {}),
    ...(disabled || isConnecting ? defaultStyles.buttonDisabled : {}),
    ...style,
  };

  return (
    <div ref={containerRef} style={defaultStyles.container} data-frost="connect-button-container">
      <button
        type="button"
        onClick={handleButtonClick}
        disabled={disabled || isConnecting}
        className={className}
        style={buttonStyles}
        data-frost="connect-button"
        data-connected={isConnected ? "true" : undefined}
        data-connecting={isConnecting ? "true" : undefined}
        aria-expanded={dropdownOpen}
        aria-haspopup={isConnected && showDropdown ? "menu" : undefined}
        onMouseEnter={e => {
          if (!disabled && !isConnecting) e.currentTarget.style.opacity = "0.9";
        }}
        onMouseLeave={e => {
          e.currentTarget.style.opacity = "1";
        }}
      >
        {isConnecting && <div style={defaultStyles.spinner} data-frost="spinner" />}
        {isConnected && wallet?.icon && (
          <img
            src={wallet.icon}
            alt={wallet.name}
            style={defaultStyles.walletIcon}
            data-frost="wallet-icon"
          />
        )}
        <span>{getButtonLabel()}</span>
        {isConnected && showDropdown && <ChevronIcon direction={dropdownOpen ? "up" : "down"} />}
      </button>

      {isConnected && showDropdown && dropdownOpen && (
        <div
          role="menu"
          className={dropdownClassName}
          style={defaultStyles.dropdown}
          data-frost="dropdown"
        >
          <div style={defaultStyles.addressDisplay} data-frost="address-display">
            {account.address}
          </div>
          <hr style={defaultStyles.dropdownDivider} />
          <button
            type="button"
            role="menuitem"
            onClick={handleCopyAddress}
            style={defaultStyles.dropdownItem}
            data-frost="dropdown-item"
            onMouseEnter={e => {
              e.currentTarget.style.backgroundColor = "var(--frost-hover-bg, #f3f4f6)";
            }}
            onMouseLeave={e => {
              e.currentTarget.style.backgroundColor = "transparent";
            }}
          >
            <CopyIcon />
            <span>{copied ? "Copied!" : "Copy Address"}</span>
          </button>
          <button
            type="button"
            role="menuitem"
            onClick={() => disconnect()}
            style={{ ...defaultStyles.dropdownItem, color: "var(--frost-danger, #ef4444)" }}
            data-frost="dropdown-item"
            data-action="disconnect"
            onMouseEnter={e => {
              e.currentTarget.style.backgroundColor = "var(--frost-hover-bg, #f3f4f6)";
            }}
            onMouseLeave={e => {
              e.currentTarget.style.backgroundColor = "transparent";
            }}
          >
            <DisconnectIcon />
            <span>Disconnect</span>
          </button>
        </div>
      )}

      <WalletModal
        open={modalOpen}
        onClose={() => setModalOpen(false)}
        onConnect={handleModalConnect}
        onError={onError}
        title={modalTitle}
      />
    </div>
  );
}
