import type { ConnectOptions, ConnectResult } from "@rialo/frost-core";
import { connect, disconnect } from "@rialo/frost-core";
import type { UseMutationResult } from "@tanstack/react-query";
import { useMutation } from "@tanstack/react-query";
import { useFrostConfig } from "../context";

export interface UseConnectWalletOptions {
  onSuccess?: (result: ConnectResult) => void;
  onError?: (error: Error) => void;
}

/**
 * Hook to connect to a wallet.
 *
 * @param options - Callbacks for success/error handling
 * @returns Mutation to trigger wallet connection
 *
 * @example
 * ```tsx
 * function ConnectButton() {
 *   const { mutate: connect, isPending } = useConnectWallet({
 *     onSuccess: () => console.log('Connected!'),
 *   });
 *
 *   return (
 *     <button onClick={() => connect({ walletName: 'Rialo' })} disabled={isPending}>
 *       Connect
 *     </button>
 *   );
 * }
 * ```
 */
export function useConnectWallet(
  options?: UseConnectWalletOptions
): UseMutationResult<ConnectResult, Error, ConnectOptions> {
  const config = useFrostConfig();

  return useMutation({
    mutationKey: ["frost", "connect"],
    mutationFn: (connectOptions: ConnectOptions) => connect(config, connectOptions),
    onSuccess: options?.onSuccess,
    onError: options?.onError,
  });
}

export interface UseDisconnectWalletOptions {
  onSuccess?: () => void;
  onError?: (error: Error) => void;
}

/**
 * Hook to disconnect the current wallet.
 *
 * @param options - Callbacks for success/error handling
 * @returns Mutation to trigger wallet disconnection
 *
 * @example
 * ```tsx
 * function DisconnectButton() {
 *   const { mutate: disconnect } = useDisconnectWallet();
 *   return <button onClick={() => disconnect()}>Disconnect</button>;
 * }
 * ```
 */
export function useDisconnectWallet(
  options?: UseDisconnectWalletOptions
): UseMutationResult<void, Error, void> {
  const config = useFrostConfig();

  return useMutation({
    mutationKey: ["frost", "disconnect"],
    mutationFn: () => disconnect(config),
    onSuccess: options?.onSuccess,
    onError: options?.onError,
  });
}
