/**
 * Base RPC client with JSON-RPC 2.0 protocol handling.
 *
 * Provides common functionality for all RPC clients including
 * request/response validation and error handling.
 */
import { RpcError } from "../errors";
import type { HttpTransport } from "../http-transport";

interface JsonRpcRequest {
  jsonrpc: "2.0";
  id: number;
  method: string;
  params: unknown[];
}

interface JsonRpcResponse<T> {
  jsonrpc: "2.0";
  id: number;
  result?: T;
  error?: {
    code: number;
    message: string;
    data?: unknown;
  };
}

/**
 * Base client with JSON-RPC protocol handling.
 *
 * All specific clients (QueryClient, TransactionClient) extend this.
 */
export class BaseRpcClient {
  protected readonly transport: HttpTransport;
  private requestId = 0;

  constructor(transport: HttpTransport) {
    this.transport = transport;
  }

  /**
   * Makes a JSON-RPC 2.0 method call with type safety.
   *
   * Handles request serialization, response validation, and error mapping.
   */
  async call<T>(method: string, params: unknown[] = []): Promise<T> {
    const requestId = this.nextRequestId();

    const request: JsonRpcRequest = {
      jsonrpc: "2.0",
      id: requestId,
      method,
      params,
    };

    const requestBody = JSON.stringify(request);
    const requestDetails = { method, params, requestId };

    // Make HTTP request with retry logic
    const data = await this.transport.request(requestBody, requestDetails);

    // Validate response structure
    if (!this.isValidJsonRpcResponse(data)) {
      throw RpcError.invalidResponse({
        ...requestDetails,
        response: data,
      });
    }

    const response = data as JsonRpcResponse<T>;

    // Check for RPC error
    if (response.error) {
      throw RpcError.fromRpcCode(response.error.code, response.error.message, {
        ...requestDetails,
        rpcData: response.error.data,
      });
    }

    // Check for result
    if (!("result" in response)) {
      throw RpcError.invalidResponse({
        ...requestDetails,
        response,
      });
    }

    return response.result as T;
  }

  /**
   * Validate JSON-RPC response structure
   */
  private isValidJsonRpcResponse(data: unknown): boolean {
    if (typeof data !== "object" || data === null) {
      return false;
    }

    const response = data as Record<string, unknown>;

    return (
      response.jsonrpc === "2.0" &&
      typeof response.id === "number" &&
      ("result" in response || "error" in response)
    );
  }

  /**
   * Generates the next request ID with Overflow Protection.
   * @returns The next request ID.
   */
  private nextRequestId(): number {
    this.requestId = (this.requestId + 1) % Number.MAX_SAFE_INTEGER;
    return this.requestId;
  }

  /**
   * Returns the configured RPC endpoint URL.
   */
  getUrl(): string {
    return this.transport.getUrl();
  }

  /**
   * Call an arbitrary RPC method with a JSON string body.
   *
   * Escape hatch for methods not yet in the typed interface.
   *
   * @param method - The RPC method name
   * @param params - JSON string of parameters
   * @returns JSON string of the result
   */
  async callWithJson(method: string, params: string): Promise<string> {
    const parsedParams = JSON.parse(params);
    const result = await this.call<unknown>(method, parsedParams);
    return JSON.stringify(result);
  }
}
