import { base58 } from "@scure/base";
import { PublicKey, type Keypair } from "../crypto";
import type { RialoClient } from "../rpc/clients/client";
import { RpcError, RpcErrorCode } from "../rpc/errors";
import { createAccount, transferInstruction } from "../transaction/instructions/system";
import { TransactionBuilder } from "../transaction/transaction-builder";
import type { Instruction } from "../transaction/types";
import { sleep } from "../utils";
import {
  BUFFER_BALANCE_FACTOR,
  DEFAULT_CHUNK_SIZE,
  DEFAULT_CONFIRMATION_BATCH_SIZE,
  DEFAULT_MAX_RETRIES,
  DEFAULT_RETRY_BASE_DELAY_MS,
  DEFAULT_RETRY_MAX_DELAY_MS,
  PROGRAM_DATA_OFFSET,
  RISCV_LOADER_PROGRAM_ID,
} from "./constants";
import { DeploymentError } from "./errors";
import {
  deployInstruction,
  retractInstruction,
  setProgramLengthInstruction,
  writeInstruction,
} from "./instructions";

export interface DeploymentConfig {
  chunkSize?: number;
  maxRetries?: number;
  retryBaseDelayMs?: number;
  retryMaxDelayMs?: number;
  confirmationBatchSize?: number;
}

export interface ProgramDeploymentOptions {
  programData: Uint8Array;
  programKeypair: Keypair;
  config?: DeploymentConfig;
}

/**
 * Calculate exponential backoff delay (matching Rust: base_ms * 1.15^attempt, capped).
 */
export function calculateBackoff(attempt: number, baseDelayMs: number, maxDelayMs: number): number {
  const delay = baseDelayMs * 1.15 ** attempt;
  return Math.min(delay, maxDelayMs);
}


/**
 * Deploys PolkaVM programs to Rialo chains.
 *
 * Matches the Rust CDK's ProgramDeployment behavior:
 * 1. Create/prepare program account
 * 2. Write bytecode in chunks with batched confirmation
 * 3. Deploy (make executable)
 */
export class ProgramDeployment {
  private readonly programData: Uint8Array;
  private readonly programKeypair: Keypair;
  private readonly chunkSize: number;
  private readonly maxRetries: number;
  private readonly retryBaseDelayMs: number;
  private readonly retryMaxDelayMs: number;
  private readonly confirmationBatchSize: number;

  constructor(options: ProgramDeploymentOptions) {
    if (options.programData.length === 0) {
      throw DeploymentError.emptyProgramData();
    }

    this.programData = options.programData;
    this.programKeypair = options.programKeypair;

    const chunkSize = options.config?.chunkSize ?? DEFAULT_CHUNK_SIZE;
    if (chunkSize <= 0) {
      throw DeploymentError.invalidChunkSize(chunkSize);
    }
    this.chunkSize = chunkSize;
    this.maxRetries = options.config?.maxRetries ?? DEFAULT_MAX_RETRIES;
    this.retryBaseDelayMs = options.config?.retryBaseDelayMs ?? DEFAULT_RETRY_BASE_DELAY_MS;
    this.retryMaxDelayMs = options.config?.retryMaxDelayMs ?? DEFAULT_RETRY_MAX_DELAY_MS;
    this.confirmationBatchSize =
      options.config?.confirmationBatchSize ?? DEFAULT_CONFIRMATION_BATCH_SIZE;
  }

  /**
   * Deploy the program to the blockchain.
   *
   * @param client - RPC client
   * @param payerKeypair - Keypair that pays for transactions and becomes the program authority
   * @returns The program's public key (derived from programKeypair)
   */
  async deploy(client: RialoClient, payerKeypair: Keypair): Promise<PublicKey> {
    const programPubkey = this.programKeypair.publicKey;
    const payerPubkey = payerKeypair.publicKey;
    const loaderPubkey = PublicKey.fromString(RISCV_LOADER_PROGRAM_ID);

    // Get config hash prefix for replay protection
    const configHashPrefix = await client.getConfigHashPrefix();

    // Calculate rent-exempt balance with safety factor
    const rentExempt = await client.getMinimumBalanceForRentExemption(
      BigInt(PROGRAM_DATA_OFFSET + this.programData.length),
    );
    const bufferBalance = BigInt(Math.floor(Number(rentExempt) * BUFFER_BALANCE_FACTOR));

    // --- Phase 1: Create or prepare program account ---
    const validFrom = BigInt(Date.now());

    const existing = await client.getAccountInfo(programPubkey).catch((e: unknown) => {
      // RialoClient.getAccountInfo throws "Account does not exist: ..." for missing accounts.
      // Any other error (network, rate-limit, server) must propagate — not silently
      // route into the account-creation path.
      if (e instanceof Error && e.message.startsWith("Account does not exist")) {
        return null;
      }
      throw e;
    });

    if (existing) {
      // --- Redeployment path ---

      // Validate owner matches RISC-V loader (same check as Rust CDK)
      if (existing.owner.toString() !== RISCV_LOADER_PROGRAM_ID) {
        throw DeploymentError.ownerMismatch(existing.owner.toString());
      }

      const ixs: Instruction[] = [];

      // Top up funds if needed
      if (existing.kelvin < bufferBalance) {
        const deficit = bufferBalance - existing.kelvin;
        ixs.push(transferInstruction(payerPubkey, programPubkey, deficit));
      }

      // Retract if currently executable
      if (existing.executable) {
        ixs.push(retractInstruction(programPubkey, payerPubkey));
      }

      // Resize (always needed for redeployment)
      ixs.push(
        setProgramLengthInstruction(
          programPubkey,
          payerPubkey,
          this.programData.length,
          payerPubkey,
        ),
      );

      const builder = TransactionBuilder.create()
        .setPayer(payerPubkey)
        .setValidFrom(validFrom)
        .setConfigHashPrefix(configHashPrefix);

      for (const ix of ixs) {
        builder.addInstruction(ix);
      }

      const tx = builder.build().sign(payerKeypair);
      await this.sendAndConfirm(client, tx.serialize());
    } else {
      // --- Initial deployment path ---
      const createIx = createAccount(
        payerPubkey,
        programPubkey,
        bufferBalance,
        0n, // space=0, the loader manages sizing via SetProgramLength
        loaderPubkey,
      );
      const setLengthIx = setProgramLengthInstruction(
        programPubkey,
        payerPubkey,
        this.programData.length,
        payerPubkey,
      );

      const tx = TransactionBuilder.create()
        .setPayer(payerPubkey)
        .setValidFrom(validFrom)
        .setConfigHashPrefix(configHashPrefix)
        .addInstruction(createIx)
        .addInstruction(setLengthIx)
        .build()
        .signAll([payerKeypair, this.programKeypair]);

      await this.sendAndConfirm(client, tx.serialize());
    }

    // Wait for buffer account to be ready
    await this.waitForBufferReady(client, programPubkey);

    // --- Phase 2: Write bytecode in chunks ---
    const chunks = this.splitIntoChunks(this.programData);
    const batchSignatures: string[] = [];

    for (let i = 0; i < chunks.length; i++) {
      const offset = i * this.chunkSize;
      const ix = writeInstruction(programPubkey, payerPubkey, offset, chunks[i]);

      const chunkValidFrom = BigInt(Date.now());
      const tx = TransactionBuilder.create()
        .setPayer(payerPubkey)
        .setValidFrom(chunkValidFrom)
        .setConfigHashPrefix(configHashPrefix)
        .addInstruction(ix)
        .build()
        .sign(payerKeypair);

      let sig: Uint8Array;
      try {
        sig = await client.sendTransaction(tx.serialize());
      } catch (e: unknown) {
        throw this.toDeploymentError(e);
      }
      batchSignatures.push(base58.encode(sig));

      // Confirm batch when full or on last chunk
      const isBatchComplete = batchSignatures.length >= this.confirmationBatchSize;
      const isLastChunk = i === chunks.length - 1;

      if (isBatchComplete || isLastChunk) {
        await this.confirmBatch(client, batchSignatures);
        batchSignatures.length = 0;
      }
    }

    // --- Phase 3: Deploy ---
    const deployIx = deployInstruction(programPubkey, payerPubkey);
    const deployValidFrom = BigInt(Date.now());
    const deployTx = TransactionBuilder.create()
      .setPayer(payerPubkey)
      .setValidFrom(deployValidFrom)
      .setConfigHashPrefix(configHashPrefix)
      .addInstruction(deployIx)
      .build()
      .sign(payerKeypair);

    await this.sendAndConfirm(client, deployTx.serialize());

    return programPubkey;
  }

  private splitIntoChunks(data: Uint8Array): Uint8Array[] {
    const chunks: Uint8Array[] = [];
    for (let offset = 0; offset < data.length; offset += this.chunkSize) {
      chunks.push(data.subarray(offset, offset + this.chunkSize));
    }
    return chunks;
  }

  private async sendAndConfirm(client: RialoClient, transaction: Uint8Array): Promise<void> {
    let result;
    try {
      result = await client.sendAndConfirmTransaction(transaction, {
        confirmMaxRetries: this.maxRetries,
        confirmRetryDelayMs: this.retryBaseDelayMs,
      });
    } catch (e: unknown) {
      throw this.toDeploymentError(e);
    }
    if (!result.executed) {
      throw DeploymentError.transactionFailed(result.err ?? "unknown error");
    }
  }

  private async confirmBatch(client: RialoClient, signatures: string[]): Promise<void> {
    let results;
    try {
      results = await Promise.all(
        signatures.map(sig => client.confirmTransaction(sig, {
          maxRetries: this.maxRetries,
          retryDelayMs: this.retryBaseDelayMs,
        })),
      );
    } catch (e: unknown) {
      throw this.toDeploymentError(e);
    }
    for (const result of results) {
      if (!result.executed) {
        throw DeploymentError.transactionFailed(result.err ?? "unknown error", {
          signature: result.signature,
        });
      }
    }
  }

  private toDeploymentError(e: unknown): DeploymentError {
    if (e instanceof DeploymentError) return e;
    if (e instanceof RpcError) {
      const details = { rpcCode: e.code, retryable: e.retryable, ...e.details };
      switch (e.code) {
        case RpcErrorCode.TRANSACTION_CONFIRMATION_TIMEOUT:
          return DeploymentError.transactionTimeout(e.message, details);
        case RpcErrorCode.TRANSACTION_REJECTED:
        case RpcErrorCode.INSUFFICIENT_FUNDS:
          return DeploymentError.transactionFailed(e.message, details);
        default:
          return DeploymentError.rpcError(e.message, details);
      }
    }
    const message = e instanceof Error ? e.message : String(e);
    return DeploymentError.rpcError(message, {
      cause: e instanceof Error ? e.constructor.name : undefined,
    });
  }

  private async waitForBufferReady(client: RialoClient, programPubkey: PublicKey): Promise<void> {
    const expectedSize = PROGRAM_DATA_OFFSET + this.programData.length;

    for (let attempt = 0; attempt < this.maxRetries; attempt++) {
      try {
        const account = await client.getAccountInfo(programPubkey);
        if (
          account.owner.toString() === RISCV_LOADER_PROGRAM_ID &&
          account.space >= BigInt(expectedSize)
        ) {
          return;
        }
      } catch (e: unknown) {
        // "Account does not exist" is expected while waiting — keep polling.
        // Any other error (network, server) should propagate.
        if (!(e instanceof Error && e.message.startsWith("Account does not exist"))) {
          throw e;
        }
      }

      const delay = calculateBackoff(attempt, this.retryBaseDelayMs, this.retryMaxDelayMs);
      await sleep(delay);
    }
    throw DeploymentError.bufferNotReady(this.maxRetries);
  }
}
