import { EncryptionError } from "./errors.js";

/**
 * Variant discriminator for RexValue Borsh serialization.
 */
export enum RexValueVariant {
	/** Plain (unencrypted) data variant */
	Plain = 0,
	/** Encrypted data variant */
	Encrypted = 1,
}

/**
 * Represents an rex value that can be plain or encrypted.
 *
 * This class provides Borsh-compatible serialization that matches
 * the Rust `RexValue` enum:
 *
 * ```rust
 * pub enum RexValue {
 *     Plain(Vec<u8>),
 *     Encrypted(Vec<u8>),
 * }
 * ```
 *
 * ## Borsh Format
 *
 * - Plain: `[0x00] [length: u32 LE] [data bytes]`
 * - Encrypted: `[0x01] [length: u32 LE] [ciphertext bytes]`
 *
 * @example
 * ```typescript
 * // Plain value (unencrypted)
 * const plain = RexValue.plain(new TextEncoder().encode("hello"));
 *
 * // Encrypted value (via DKG threshold encryption)
 * const encrypted = RexValue.encrypted(ciphertextBytes);
 *
 * // Serialize to Borsh
 * const borsh = plain.toBorsh();
 *
 * // Deserialize from Borsh
 * const restored = RexValue.fromBorsh(borsh);
 * ```
 */
export class RexValue {
	private readonly variant: RexValueVariant;
	private readonly data: Uint8Array;

	private constructor(variant: RexValueVariant, data: Uint8Array) {
		this.variant = variant;
		this.data = data;
	}

	/**
	 * Create a plain (unencrypted) RexValue from raw bytes.
	 *
	 * @param data - The raw byte data
	 * @returns A new RexValue with Plain variant
	 */
	static plain(data: Uint8Array): RexValue {
		return new RexValue(RexValueVariant.Plain, data);
	}

	/**
	 * Create a plain (unencrypted) RexValue from a UTF-8 string.
	 *
	 * @param s - The string to encode
	 * @returns A new RexValue with Plain variant
	 */
	static plainString(s: string): RexValue {
		return new RexValue(
			RexValueVariant.Plain,
			new TextEncoder().encode(s),
		);
	}

	/**
	 * Create an encrypted RexValue from a DKG threshold-encrypted payload.
	 *
	 * @param ciphertext - The DKG-encrypted payload bytes (`[0x02] || borsh(DkgEncryptedPayload)`)
	 * @returns A new RexValue with Encrypted variant
	 */
	static encrypted(ciphertext: Uint8Array): RexValue {
		return new RexValue(RexValueVariant.Encrypted, ciphertext);
	}

	/**
	 * Check if this is a plain (unencrypted) value.
	 */
	isPlain(): boolean {
		return this.variant === RexValueVariant.Plain;
	}

	/**
	 * Check if this is an encrypted value.
	 */
	isEncrypted(): boolean {
		return this.variant === RexValueVariant.Encrypted;
	}

	/**
	 * Get the variant type.
	 */
	getVariant(): RexValueVariant {
		return this.variant;
	}

	/**
	 * Get the raw bytes (plaintext or ciphertext).
	 *
	 * For Plain values, returns the plaintext.
	 * For Encrypted values, returns the ciphertext.
	 */
	asBytes(): Uint8Array {
		return this.data;
	}

	/**
	 * Try to decode the plain value as a UTF-8 string.
	 *
	 * @returns The decoded string, or null if encrypted or not valid UTF-8
	 */
	asString(): string | null {
		if (!this.isPlain()) {
			return null;
		}
		try {
			return new TextDecoder("utf-8", { fatal: true }).decode(this.data);
		} catch {
			return null;
		}
	}

	/**
	 * Serialize to Borsh format.
	 *
	 * Format: `[variant: u8] [length: u32 LE] [data bytes]`
	 *
	 * @returns The Borsh-serialized bytes
	 */
	toBorsh(): Uint8Array {
		// 1 byte variant + 4 bytes length + data
		const result = new Uint8Array(1 + 4 + this.data.length);

		// Write variant (1 byte)
		result[0] = this.variant;

		// Write length as u32 LE (4 bytes)
		const dataView = new DataView(result.buffer);
		dataView.setUint32(1, this.data.length, true);

		// Write data
		result.set(this.data, 5);

		return result;
	}

	/**
	 * Deserialize from Borsh format.
	 *
	 * @param data - The Borsh-serialized bytes
	 * @returns A new RexValue
	 * @throws {EncryptionError} If deserialization fails
	 */
	static fromBorsh(data: Uint8Array): RexValue {
		if (data.length < 5) {
			throw EncryptionError.borshDeserializeFailed(
				new Error(`Buffer too short: expected at least 5 bytes, got ${data.length}`),
			);
		}

		const variant = data[0];
		if (variant !== RexValueVariant.Plain && variant !== RexValueVariant.Encrypted) {
			throw EncryptionError.invalidRexValue(variant);
		}

		const dataView = new DataView(data.buffer, data.byteOffset, data.byteLength);
		const length = dataView.getUint32(1, true);

		if (data.length < 5 + length) {
			throw EncryptionError.borshDeserializeFailed(
				new Error(`Buffer too short: expected ${5 + length} bytes, got ${data.length}`),
			);
		}

		const payload = data.slice(5, 5 + length);

		return new RexValue(variant as RexValueVariant, payload);
	}
}
