/**
 * Error handling for the Rialo CDK.
 *
 * This module defines the common error types used throughout the Rialo CDK.
 * It provides a centralized error handling mechanism for all operations.
 */

/**
 * Structured RPC error information parsed from JSON-RPC error responses.
 */
export interface RpcErrorDetails {
	/** HTTP status code (e.g., 200, 422, 500) */
	status?: number;
	/** JSON-RPC error code (e.g., -32002) */
	code: number;
	/** Human-readable error message */
	message: string;
}

/**
 * Error types for different subsystems in the Rialo CDK.
 */
export enum RialoErrorType {
	/** Errors related to file or system I/O operations */
	IO = "IO",
	/** Errors occurring during RPC communication with blockchain nodes */
	RPC = "RPC",
	/** Errors related to public key parsing or validation */
	PARSE_PUBKEY = "PARSE_PUBKEY",
	/** Errors related to blockhash parsing or validation */
	INVALID_BLOCKHASH_FORMAT = "INVALID_BLOCKHASH_FORMAT",
	/** Errors related to wallet operations such as creation, loading, or signing */
	WALLET = "WALLET",
	/** Errors related to configuration loading, parsing, or validation */
	CONFIG = "CONFIG",
	/** Errors occurring during transaction building, signing, or submission */
	TRANSACTION = "TRANSACTION",
	/** Network-related errors, including HTTP client errors */
	NETWORK = "NETWORK",
	/** Errors related to password handling, validation, or verification */
	PASSWORD = "PASSWORD",
	/** Errors related to encryption or decryption operations */
	ENCRYPTION = "ENCRYPTION",
	/** Errors occurring during JSON parsing, serialization, or deserialization */
	JSON = "JSON",
	/** Errors related to BIP32 key derivation */
	BIP32 = "BIP32",
	/** Errors related to invalid input parameters or data */
	INVALID_INPUT = "INVALID_INPUT",
	/** Errors related to serialization/deserialization */
	SERIALIZATION = "SERIALIZATION",
}

/**
 * Base error class for all Rialo CDK errors.
 *
 * Provides structured error handling with type categorization and optional
 * cause tracking for error chains. Use the static factory methods for
 * consistent error creation across the SDK.
 *
 * @example
 * ```typescript
 * // Create typed errors using factory methods
 * throw RialoError.invalidInput("Amount must be positive");
 * throw RialoError.network("Connection failed", originalError);
 * throw RialoError.rpc({ code: -32002, message: "Invalid params" });
 *
 * // Handle errors with type information
 * try {
 *   await client.sendTransaction(tx);
 * } catch (error) {
 *   if (error instanceof RialoError && error.type === RialoErrorType.NETWORK) {
 *     console.log("Network error, retrying...");
 *   }
 * }
 * ```
 */
export class RialoError extends Error {
	public readonly type: RialoErrorType;
	public readonly cause?: Error;
	public readonly details?: RpcErrorDetails;

	public constructor(
		type: RialoErrorType,
		message: string,
		cause?: Error,
		details?: RpcErrorDetails,
	) {
		super(message);
		this.name = "RialoError";
		this.type = type;
		this.cause = cause;
		this.details = details;

		// Maintains proper stack trace for where our error was thrown (only available on V8)
		if (Error.captureStackTrace) {
			Error.captureStackTrace(this, RialoError);
		}
	}

	/**
	 * Creates an IO error.
	 */
	public static io(message: string, cause?: Error): RialoError {
		return new RialoError(RialoErrorType.IO, `I/O error: ${message}`, cause);
	}

	/**
	 * Creates an RPC error.
	 */
	public static rpc(details: RpcErrorDetails): RialoError {
		let message: string = details.message;
		if (details.status !== undefined) {
			message = `${details.message} [HTTP ${details.status} code ${details.code}]`;
		} else if (details.code !== 0) {
			message = `${details.message} (code ${details.code})`;
		}
		return new RialoError(
			RialoErrorType.RPC,
			`RPC error: ${message}`,
			undefined,
			details,
		);
	}

	/**
	 * Creates a public key parsing error.
	 */
	public static parsePubkey(message: string): RialoError {
		return new RialoError(
			RialoErrorType.PARSE_PUBKEY,
			`Pubkey error: ${message}`,
		);
	}

	/**
	 * Creates a blockhash format error.
	 */
	public static invalidBlockhash(message: string): RialoError {
		return new RialoError(
			RialoErrorType.INVALID_BLOCKHASH_FORMAT,
			`Invalid blockhash format: ${message}`,
		);
	}

	/**
	 * Creates a wallet error.
	 */
	public static wallet(message: string): RialoError {
		return new RialoError(RialoErrorType.WALLET, `Wallet error: ${message}`);
	}

	/**
	 * Creates a configuration error.
	 */
	public static config(message: string): RialoError {
		return new RialoError(RialoErrorType.CONFIG, `Config error: ${message}`);
	}

	/**
	 * Creates a transaction error.
	 */
	public static transaction(message: string): RialoError {
		return new RialoError(
			RialoErrorType.TRANSACTION,
			`Transaction error: ${message}`,
		);
	}

	/**
	 * Creates a network error.
	 */
	public static network(message: string, cause?: Error): RialoError {
		return new RialoError(
			RialoErrorType.NETWORK,
			`Network error: ${message}`,
			cause,
		);
	}

	/**
	 * Creates a password error.
	 */
	public static password(message: string): RialoError {
		return new RialoError(
			RialoErrorType.PASSWORD,
			`Password error: ${message}`,
		);
	}

	/**
	 * Creates an encryption error.
	 */
	public static encryption(message: string): RialoError {
		return new RialoError(
			RialoErrorType.ENCRYPTION,
			`Encryption error: ${message}`,
		);
	}

	/**
	 * Creates a JSON error.
	 */
	public static json(message: string, cause?: Error): RialoError {
		return new RialoError(RialoErrorType.JSON, `JSON error: ${message}`, cause);
	}

	/**
	 * Creates a BIP32 error.
	 */
	public static bip32(message: string): RialoError {
		return new RialoError(RialoErrorType.BIP32, `BIP32 error: ${message}`);
	}

	/**
	 * Creates an invalid input error.
	 */
	public static invalidInput(message: string): RialoError {
		return new RialoError(
			RialoErrorType.INVALID_INPUT,
			`Invalid input: ${message}`,
		);
	}

	/**
	 * Creates a serialization error.
	 */
	public static serialization(message: string): RialoError {
		return new RialoError(
			RialoErrorType.SERIALIZATION,
			`Serialization error: ${message}`,
		);
	}
}
