import type { SignMessageOptions, SignMessageResult } from "@rialo/frost-core";
import { signMessage } from "@rialo/frost-core";
import type { UseMutationResult } from "@tanstack/react-query";
import { useMutation } from "@tanstack/react-query";
import { useFrostConfig } from "../context";

export interface UseSignMessageOptions {
  onSuccess?: (result: SignMessageResult) => void;
  onError?: (error: Error) => void;
}

/**
 * Hook to sign an arbitrary message.
 *
 * @param options - Callbacks for success/error handling
 * @returns Mutation to trigger message signing
 *
 * @example
 * ```tsx
 * function SignButton() {
 *   const { mutate: sign, isPending } = useSignMessage({
 *     onSuccess: (result) => console.log('Signature:', result.signature),
 *   });
 *
 *   return (
 *     <button onClick={() => sign({ message: 'Hello World' })} disabled={isPending}>
 *       Sign Message
 *     </button>
 *   );
 * }
 * ```
 */
export function useSignMessage(
  options?: UseSignMessageOptions
): UseMutationResult<SignMessageResult, Error, SignMessageOptions> {
  const config = useFrostConfig();

  return useMutation({
    mutationKey: ["frost", "signMessage"],
    mutationFn: (msgOptions: SignMessageOptions) => signMessage(config, msgOptions),
    onSuccess: options?.onSuccess,
    onError: options?.onError,
  });
}
