import type { ConnectResult, WalletEntity } from "@rialo/frost-core";
import type { CSSProperties, KeyboardEvent, MouseEvent, ReactNode } from "react";
import { useCallback, useEffect, useRef } from "react";
import { useConnectionStatus } from "../hooks/useConnectionStatus";
import { useConnectWallet } from "../hooks/useConnectWallet";
import { useWallets } from "../hooks/useWallets";
import { CloseIcon, WalletPlaceholderIcon } from "./icons";

export interface WalletModalProps {
  /** Whether the modal is open */
  open: boolean;
  /** Callback when modal should close */
  onClose: () => void;
  /** Callback when wallet connection succeeds */
  onConnect?: (walletName: string, address: string) => void;
  /** Callback when wallet connection fails */
  onError?: (error: Error, walletName: string) => void;
  /** Modal title */
  title?: string;
  /** Additional class name for the modal overlay */
  className?: string;
  /** Additional class name for the modal content */
  contentClassName?: string;
  /** Custom styles for the modal */
  style?: CSSProperties;
  /** Render prop for custom wallet item rendering */
  renderWallet?: (wallet: WalletEntity, connect: () => void, isConnecting: boolean) => ReactNode;
}

const defaultStyles: Record<string, CSSProperties> = {
  overlay: {
    position: "fixed",
    inset: 0,
    backgroundColor: "var(--frost-overlay-bg, rgba(0, 0, 0, 0.5))",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    zIndex: "var(--frost-z-index, 9999)" as unknown as number,
    padding: "1rem",
  },
  content: {
    backgroundColor: "var(--frost-modal-bg, #ffffff)",
    borderRadius: "var(--frost-border-radius, 12px)",
    boxShadow: "var(--frost-shadow, 0 4px 24px rgba(0, 0, 0, 0.15))",
    maxWidth: "var(--frost-modal-max-width, 400px)",
    width: "100%",
    maxHeight: "80vh",
    overflow: "hidden",
    display: "flex",
    flexDirection: "column",
  },
  header: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    padding: "1rem 1.25rem",
    borderBottom: "1px solid var(--frost-border-color, #e5e7eb)",
  },
  title: {
    margin: 0,
    fontSize: "1.125rem",
    fontWeight: 600,
    color: "var(--frost-text-color, #111827)",
  },
  closeButton: {
    background: "none",
    border: "none",
    padding: "0.5rem",
    cursor: "pointer",
    borderRadius: "var(--frost-border-radius-sm, 6px)",
    color: "var(--frost-text-secondary, #6b7280)",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    transition: "background-color 0.15s ease",
  },
  walletList: {
    listStyle: "none",
    margin: 0,
    padding: "0.5rem",
    overflowY: "auto",
    flex: 1,
  },
  walletItem: {
    display: "flex",
    alignItems: "center",
    gap: "0.75rem",
    padding: "0.875rem 1rem",
    borderRadius: "var(--frost-border-radius-sm, 8px)",
    cursor: "pointer",
    border: "none",
    background: "none",
    width: "100%",
    textAlign: "left",
    transition: "background-color 0.15s ease",
    color: "var(--frost-text-color, #111827)",
  },
  walletIcon: {
    width: 40,
    height: 40,
    borderRadius: "var(--frost-border-radius-sm, 8px)",
    objectFit: "contain",
    backgroundColor: "var(--frost-icon-bg, #f3f4f6)",
  },
  walletInfo: {
    flex: 1,
    minWidth: 0,
  },
  walletName: {
    margin: 0,
    fontSize: "0.9375rem",
    fontWeight: 500,
    color: "inherit",
  },
  walletStatus: {
    margin: 0,
    fontSize: "0.8125rem",
    color: "var(--frost-text-secondary, #6b7280)",
  },
  spinner: {
    width: 20,
    height: 20,
    border: "2px solid var(--frost-border-color, #e5e7eb)",
    borderTopColor: "var(--frost-primary, #3b82f6)",
    borderRadius: "50%",
    animation: "frost-spin 0.8s linear infinite",
  },
  emptyState: {
    padding: "2rem 1rem",
    textAlign: "center",
    color: "var(--frost-text-secondary, #6b7280)",
  },
};

const SPINNER_KEYFRAMES = `
@keyframes frost-spin {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}
`;

let stylesInjected = false;

function injectStyles(): void {
  if (stylesInjected || typeof document === "undefined") return;
  const style = document.createElement("style");
  style.textContent = SPINNER_KEYFRAMES;
  document.head.appendChild(style);
  stylesInjected = true;
}

export function WalletModal({
  open,
  onClose,
  onConnect,
  onError,
  title = "Connect Wallet",
  className,
  contentClassName,
  style,
  renderWallet,
}: WalletModalProps): ReactNode {
  const wallets = useWallets();
  const status = useConnectionStatus();
  const {
    mutate: connect,
    variables: connectingWallet,
    isPending,
  } = useConnectWallet({
    onSuccess: (result: ConnectResult) => {
      onConnect?.(result.walletName, result.accountAddress);
    },
    onError: (error: Error) => {
      onError?.(error, connectingWallet?.walletName ?? "unknown");
    },
  });

  const modalRef = useRef<HTMLDivElement>(null);
  const previousActiveElement = useRef<HTMLElement | null>(null);
  const wasOpen = useRef(false);

  useEffect(() => {
    injectStyles();
  }, []);

  // Handle focus restoration when modal closes
  useEffect(() => {
    if (open && !wasOpen.current) {
      // Modal just opened - save the active element
      previousActiveElement.current = document.activeElement as HTMLElement;
      modalRef.current?.focus();
    } else if (!open && wasOpen.current) {
      // Modal just closed - restore focus
      previousActiveElement.current?.focus();
    }
    wasOpen.current = open;
  }, [open]);

  // Handle keyboard and scroll lock
  useEffect(() => {
    if (!open) return;

    const handleKeyDown = (e: globalThis.KeyboardEvent): void => {
      if (e.key === "Escape") {
        onClose();
        return;
      }

      if (e.key === "Tab" && modalRef.current) {
        const focusableElements = modalRef.current.querySelectorAll<HTMLElement>(
          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );
        const firstElement = focusableElements[0];
        const lastElement = focusableElements[focusableElements.length - 1];

        if (e.shiftKey && document.activeElement === firstElement) {
          e.preventDefault();
          lastElement?.focus();
        } else if (!e.shiftKey && document.activeElement === lastElement) {
          e.preventDefault();
          firstElement?.focus();
        }
      }
    };

    document.addEventListener("keydown", handleKeyDown);
    const originalOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      document.body.style.overflow = originalOverflow;
    };
  }, [open, onClose]);

  const handleOverlayClick = useCallback(
    (e: MouseEvent<HTMLDivElement>) => {
      if (e.target === e.currentTarget) {
        onClose();
      }
    },
    [onClose]
  );

  const handleWalletClick = useCallback(
    (walletName: string) => {
      connect({ walletName });
    },
    [connect]
  );

  const handleWalletKeyDown = useCallback(
    (e: KeyboardEvent<HTMLButtonElement>, walletName: string) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault();
        connect({ walletName });
      }
    },
    [connect]
  );

  if (!open) return null;

  const isConnecting = status === "connecting" || isPending;

  return (
    // biome-ignore lint/a11y/useKeyWithClickEvents: <modal>
    <div
      role="dialog"
      aria-modal="true"
      aria-labelledby="frost-modal-title"
      className={className}
      style={{ ...defaultStyles.overlay, ...style }}
      onClick={handleOverlayClick}
    >
      <div
        ref={modalRef}
        className={contentClassName}
        style={defaultStyles.content}
        tabIndex={-1}
        data-frost="modal-content"
      >
        <div style={defaultStyles.header} data-frost="modal-header">
          <h2 id="frost-modal-title" style={defaultStyles.title}>
            {title}
          </h2>
          <button
            type="button"
            onClick={onClose}
            style={defaultStyles.closeButton}
            aria-label="Close modal"
            data-frost="modal-close"
          >
            <CloseIcon />
          </button>
        </div>

        <ul style={defaultStyles.walletList} data-frost="wallet-list">
          {wallets.length === 0 ? (
            <li style={defaultStyles.emptyState} data-frost="empty-state">
              <p>No wallets detected.</p>
              <p style={{ marginTop: "0.5rem", fontSize: "0.875rem" }}>
                Please install a Rialo-compatible wallet extension.
              </p>
            </li>
          ) : (
            wallets.map(wallet => {
              const isThisConnecting = isConnecting && connectingWallet?.walletName === wallet.name;

              if (renderWallet) {
                return (
                  <li key={wallet.name}>
                    {renderWallet(wallet, () => handleWalletClick(wallet.name), isThisConnecting)}
                  </li>
                );
              }

              return (
                <li key={wallet.name}>
                  <button
                    type="button"
                    onClick={() => handleWalletClick(wallet.name)}
                    onKeyDown={(e: KeyboardEvent<HTMLButtonElement>) =>
                      handleWalletKeyDown(e, wallet.name)
                    }
                    disabled={isConnecting}
                    style={{
                      ...defaultStyles.walletItem,
                      opacity: isConnecting && !isThisConnecting ? 0.5 : 1,
                      cursor: isConnecting ? "not-allowed" : "pointer",
                    }}
                    data-frost="wallet-item"
                    data-connecting={isThisConnecting ? "true" : undefined}
                    onMouseEnter={(e: MouseEvent<HTMLButtonElement>) => {
                      if (!isConnecting) {
                        e.currentTarget.style.backgroundColor = "var(--frost-hover-bg, #f3f4f6)";
                      }
                    }}
                    onMouseLeave={(e: MouseEvent<HTMLButtonElement>) => {
                      e.currentTarget.style.backgroundColor = "transparent";
                    }}
                  >
                    {wallet.icon ? (
                      <img
                        src={wallet.icon}
                        alt={`${wallet.name} icon`}
                        style={defaultStyles.walletIcon}
                        data-frost="wallet-icon"
                      />
                    ) : (
                      <div
                        style={{
                          ...defaultStyles.walletIcon,
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          color: "var(--frost-text-secondary, #6b7280)",
                        }}
                        data-frost="wallet-icon-placeholder"
                      >
                        <WalletPlaceholderIcon />
                      </div>
                    )}

                    <div style={defaultStyles.walletInfo}>
                      <p style={defaultStyles.walletName}>{wallet.name}</p>
                      {wallet.installedVersion && (
                        <p style={defaultStyles.walletStatus}>v{wallet.installedVersion}</p>
                      )}
                    </div>

                    {isThisConnecting && <div style={defaultStyles.spinner} data-frost="spinner" />}
                  </button>
                </li>
              );
            })
          )}
        </ul>
      </div>
    </div>
  );
}
