/**
 * Main Rialo RPC client for blockchain interactions.
 */
import type { PublicKey } from "../../crypto";
import { RpcClient } from "../../generated/rpc-client";
import type {
	AccountFilter,
	AccountInfo,
	AllAccountsEntry,
	BlockInfo,
	ClusterNodeInfo,
	ConfigHashPrefix,
	ConfirmedTransaction,
	ConfirmTransactionOptions,
	ConnectedNode,
	EpochInfo,
	FeeResponse,
	GetAccountsByOwnerConfig,
	GetAllAccountsConfig,
	GetBlockConfig,
	GetSignaturesForAddressConfig,
	GetTransactionsConfig,
	GetValidatorAccountsRequest,
	GetWorkflowLineageRequest,
	GetWorkflowLineageResponse,
	Hash,
	IsBlockhashValidResponse,
	Kelvin,
	OptionalAccountInfo,
	OwnerAccount,
	PaginationInfo,
	RexInfoAndDuties,
	SecretSharingPubkey,
	SendAndConfirmOptions,
	SendTransactionOptions,
	Signature,
	SignatureInfo,
	SignatureStatus,
	StakeAccountInfo,
	SubmitEpochChangeRequest,
	SubmitEpochChangeResponse,
	Subscription,
	TokenBalance,
	TransactionInfo,
	TransactionResponse,
	TriggeredTransaction,
	ValidatorAccountInfo,
	ValidatorHealth,
} from "../../generated/types";
import type { HttpTransport } from "../http-transport";
import type { ChainDefinition, IdentifierString } from "./config";
import type { AccountFilterParam } from "./query-client";
import { QueryRpcClient } from "./query-client";
import { TransactionRpcClient } from "./transaction-client";

/**
 * High-level Rialo RPC client for blockchain interactions.
 *
 * Provides a unified interface for querying blockchain state and
 * sending transactions. Internally delegates to specialized clients
 * (QueryRpcClient, TransactionRpcClient) for modular organization.
 *
 * @example
 * ```typescript
 * import { createRialoClient, RIALO_DEVNET_CHAIN } from '@rialo/ts-cdk';
 *
 * const client = createRialoClient({ chain: RIALO_DEVNET_CHAIN });
 *
 * // Query operations
 * const balance = await client.getBalance(publicKey);
 * const chainId = client.getChainIdentifier();
 *
 * // Transaction operations
 * const signature = await client.sendTransaction(signedTx);
 * ```
 */
export class RialoClient extends RpcClient {
	private readonly queryClient: QueryRpcClient;
	private readonly transactionClient: TransactionRpcClient;
	private readonly transport: HttpTransport;
	private readonly chain: ChainDefinition;

	constructor(transport: HttpTransport, chain: ChainDefinition) {
		super();
		this.chain = chain;
		this.transport = transport;
		this.queryClient = new QueryRpcClient(transport);
		this.transactionClient = new TransactionRpcClient(transport);
	}

	/**
	 * Returns the configured RPC endpoint URL.
	 */
	getUrl(): string {
		return this.transport.getUrl();
	}

	/**
	 * Returns the chain identifier.
	 */
	getChainIdentifier(): IdentifierString {
		return this.chain.id;
	}

	/**
	 * Returns the chain configuration.
	 */
	getChainConfig(): ChainDefinition {
		return this.chain;
	}

	/**
	 * Retrieves the balance of an account in kelvins (smallest unit).
	 */
	async getBalance(pubkey: PublicKey): Promise<Kelvin> {
		return await this.queryClient.getBalance(pubkey);
	}

	/**
	 * Retrieves detailed information about an account.
	 *
	 * @returns Account info or null if account doesn't exist
	 */
	async getAccountInfo(pubkey: PublicKey): Promise<AccountInfo> {
		const result = await this.queryClient.getAccountInfo(pubkey);
		if (!result) {
			throw new Error(`Account does not exist: ${pubkey}`);
		}
		return result;
	}

	/**
	 * Retrieves the current block height.
	 */
	async getBlockHeight(): Promise<bigint> {
		return await this.queryClient.getBlockHeight();
	}

	/**
	 * Retrieves the current block height with advanced configuration.
	 */
	async getBlockHeightWithConfig(
		minContextSlot: bigint | undefined,
	): Promise<bigint> {
		return await this.queryClient.getBlockHeightWithConfig(minContextSlot);
	}

	/**
	 * Retrieves the signatures for an address.
	 */
	async getSignaturesForAddress(
		address: PublicKey,
		config: GetSignaturesForAddressConfig | undefined,
	): Promise<SignatureInfo[]> {
		return await this.queryClient.getSignaturesForAddress(address, config);
	}

	/**
	 * Retrieves detailed information about a transaction.
	 *
	 * @returns Full transaction response
	 */
	async getTransaction(sig: Signature): Promise<TransactionResponse> {
		return await this.queryClient.getTransactionDetails(sig);
	}

	/**
	 * Retrieves the total number of transactions processed since genesis.
	 */
	async getTransactionCount(): Promise<bigint> {
		return await this.queryClient.getTransactionCount();
	}

	/**
	 * Retrieves the status of multiple transaction signatures.
	 */
	async getSignatureStatuses(
		signatures: Signature[],
	): Promise<(SignatureStatus | undefined)[]> {
		// Convert Uint8Array signatures to base58 strings
		const { base58 } = await import("@scure/base");
		const sigStrings = signatures.map((s) => base58.encode(s));
		const results = await this.queryClient.getSignatureStatuses(sigStrings);
		// Filter out null entries (unknown signatures) per spec behaviour
		return results.filter((s): s is SignatureStatus => s !== null);
	}

	/**
	 * Retrieves current epoch information.
	 */
	async getEpochInfo(): Promise<EpochInfo> {
		return await this.queryClient.getEpochInfo();
	}

	/**
	 * Checks the health status of the RPC node.
	 *
	 * @returns "ok" if healthy, error message otherwise
	 */
	async getHealth(): Promise<string> {
		return await this.queryClient.getHealth();
	}

	/**
	 * Submits a signed transaction to the blockchain.
	 *
	 * @param transaction - Serialized signed transaction bytes
	 * @param options - Transaction submission options
	 * @returns Transaction signature
	 */
	async sendTransaction(
		transaction: Uint8Array,
		options?: Partial<SendTransactionOptions>,
	): Promise<Signature> {
		const sigStr = await this.transactionClient.sendTransaction(
			transaction,
			options,
		);
		const { base58 } = await import("@scure/base");
		return base58.decode(sigStr);
	}

	/**
	 * Requests an airdrop of tokens to an account.
	 *
	 * **Note**: Only available on devnet and testnet.
	 *
	 * @param pubkey - Account to receive the airdrop
	 * @param amount - Amount in kelvins (smallest unit)
	 * @returns Transaction signature
	 */
	async requestAirdrop(pubkey: PublicKey, amount: Kelvin): Promise<Signature> {
		const sigStr = await this.transactionClient.requestAirdrop(pubkey, amount);
		const { base58 } = await import("@scure/base");
		return base58.decode(sigStr);
	}

	/**
	 * Submits a signed transaction and waits for confirmation.
	 *
	 * @param transaction - Serialized signed transaction bytes
	 * @param options - Transaction submission and confirmation options
	 * @returns Confirmed transaction details
	 * @throws {TransactionFailedError} If the transaction fails on-chain
	 * @throws {TransactionConfirmationTimeoutError} If confirmation times out
	 *
	 * @example
	 * ```typescript
	 * const result = await client.sendAndConfirmTransaction(signedTx);
	 * console.log(`Confirmed in slot ${result.slot}`);
	 * ```
	 */
	async sendAndConfirmTransaction(
		transaction: Uint8Array,
		options?: Partial<SendAndConfirmOptions>,
	): Promise<ConfirmedTransaction> {
		return await this.transactionClient.sendAndConfirmTransaction(
			transaction,
			options,
		);
	}

	/**
	 * Waits for a transaction to be confirmed.
	 *
	 * @param signature - Transaction signature to monitor
	 * @param options - Confirmation options
	 * @returns Confirmed transaction details
	 */
	async confirmTransaction(
		sig: string,
		options?: Partial<ConfirmTransactionOptions>,
	): Promise<ConfirmedTransaction> {
		return await this.transactionClient.confirmTransaction(sig, options);
	}

	/**
	 * Requests an airdrop and waits for confirmation.
	 *
	 * **Note**: Only available on devnet and testnet.
	 */
	async requestAirdropAndConfirm(
		pubkey: PublicKey,
		amount: Kelvin,
	): Promise<ConfirmedTransaction> {
		return await this.transactionClient.requestAirdropAndConfirm(
			pubkey,
			amount,
		);
	}

	/**
	 * Calculate the minimum balance required for an account to be rent-exempt.
	 *
	 * @param accountDataSize - The size of the account data in bytes
	 * @returns The minimum balance in kelvins required for rent exemption
	 */
	async getMinimumBalanceForRentExemption(dataSize: bigint): Promise<bigint> {
		return await this.queryClient.getMinimumBalanceForRentExemption(
			Number(dataSize),
		);
	}

	/**
	 * Get the fee required to process a specific message.
	 *
	 * @param message - Base64-encoded serialized versioned message
	 * @returns Fee response with value in kelvins
	 */
	async getFeeForMessage(message: string): Promise<FeeResponse> {
		const value = await this.queryClient.getFeeForMessage(message);
		return { value: value ?? undefined };
	}

	/**
	 * Get information for multiple accounts in a single request.
	 *
	 * @param pubkeys - Array of public keys to query (1-100)
	 * @returns Account information for each address
	 */
	async getMultipleAccounts(
		pubkeys: PublicKey[],
	): Promise<OptionalAccountInfo[]> {
		const results = await this.queryClient.getMultipleAccounts(pubkeys);
		// Convert null → undefined to match OptionalAccountInfo type
		return results.map((r) =>
			r === null ? undefined : r,
		) as OptionalAccountInfo[];
	}

	/**
	 * Get all accounts owned by a specific program or address.
	 *
	 * @param owner - Program ID or owner public key
	 * @param filter - Filter type (programAccounts or tokenAccounts)
	 * @param config - Optional configuration for pagination and encoding
	 * @returns Tuple of accounts and optional pagination info
	 */
	async getAccountsByOwner(
		owner: PublicKey,
		filter: AccountFilter | undefined,
		config: GetAccountsByOwnerConfig | undefined,
	): Promise<[OwnerAccount[], PaginationInfo | undefined]> {
		// Convert generated string union AccountFilter to the serde-compatible param
		const filterParam: AccountFilterParam =
			filter === "tokenAccounts"
				? { type: "tokenAccounts" }
				: { type: "programAccounts" };
		return await this.queryClient.getAccountsByOwner(
			owner,
			filterParam,
			config,
		);
	}

	/**
	 * Get workflow lineage information for tracking execution history.
	 *
	 * @param request - Workflow lineage request with signature and options
	 * @returns Workflow lineage tree with nodes and metadata
	 */
	async getWorkflowLineage(
		request: GetWorkflowLineageRequest,
	): Promise<GetWorkflowLineageResponse> {
		return await this.queryClient.getWorkflowLineage(request);
	}

	/**
	 * Get subscription for a given subscriber address and nonce.
	 *
	 * @param subscriber - The subscriber's public key
	 * @param nonce - The nonce identifying the subscription
	 * @returns The subscription for the subscriber and nonce
	 */
	async getSubscription(
		subscriber: PublicKey,
		nonce: string,
	): Promise<Subscription> {
		return await this.queryClient.getSubscription(subscriber, nonce);
	}

	/**
	 * Get transactions triggered by a subscription account.
	 *
	 * @param subscriptionAccount - The subscription account public key
	 * @param limit - Optional limit on transactions returned
	 * @returns Triggered transactions for the subscription
	 */
	async getTriggeredTransactions(
		subscriptionAccount: PublicKey,
		limit: number | undefined,
	): Promise<TriggeredTransaction[]> {
		return await this.queryClient.getTriggeredTransactions(
			subscriptionAccount,
			limit,
		);
	}

	/**
	 * Gets paginated transactions from the blockchain.
	 */
	async getTransactions(
		config: GetTransactionsConfig | undefined,
	): Promise<TransactionInfo[]> {
		return await this.queryClient.getTransactions(config);
	}

	/**
	 * Checks if a blockhash is still valid for transaction submission.
	 */
	async isBlockhashValid(blockhash: Hash): Promise<IsBlockhashValidResponse> {
		return await this.queryClient.isBlockhashValid(blockhash);
	}

	/**
	 * Gets the health status of the validator.
	 */
	async getValidatorHealth(): Promise<ValidatorHealth> {
		return await this.queryClient.getValidatorHealth();
	}

	/**
	 * Gets the list of full nodes connected to the validator or full node.
	 */
	async getConnectedFullNodes(): Promise<ConnectedNode[]> {
		return await this.queryClient.getConnectedFullNodes();
	}

	/**
	 * Gets the active secret-sharing public key metadata.
	 */
	async getSecretSharingPubkey(): Promise<SecretSharingPubkey> {
		return await this.queryClient.getSecretSharingPubkey();
	}

	/**
	 * Gets the config hash prefix for protecting against replay attacks.
	 */
	async getConfigHashPrefix(): Promise<ConfigHashPrefix> {
		return await this.queryClient.getConfigHashPrefix();
	}

	/**
	 * Submits an epoch change transaction (admin-only).
	 */
	async sendAdminTransaction(
		request: SubmitEpochChangeRequest,
	): Promise<SubmitEpochChangeResponse> {
		return await this.transactionClient.sendAdminTransaction(request);
	}

	/**
	 * Gets all accounts in the system.
	 */
	async getAllAccounts(
		config: GetAllAccountsConfig | undefined,
	): Promise<AllAccountsEntry[]> {
		return await this.queryClient.getAllAccounts(config);
	}

	/**
	 * Gets a block by its height.
	 */
	async getBlock(
		blockHeight: bigint,
		config: GetBlockConfig | undefined,
	): Promise<BlockInfo> {
		return await this.queryClient.getBlock(blockHeight, config);
	}

	/**
	 * Gets a list of confirmed block heights in a range.
	 */
	async getBlocks(
		startHeight: bigint,
		endHeight: bigint | undefined,
	): Promise<bigint[]> {
		return await this.queryClient.getBlocks(startHeight, endHeight);
	}

	/**
	 * Gets detailed information about a stake account.
	 */
	async getStakeAccount(
		pubkey: PublicKey,
	): Promise<StakeAccountInfo | undefined> {
		return await this.queryClient.getStakeAccount(pubkey);
	}

	/**
	 * Gets all registered validator accounts.
	 */
	async getValidatorAccounts(
		request: GetValidatorAccountsRequest,
	): Promise<ValidatorAccountInfo[]> {
		return await this.queryClient.getValidatorAccounts(request);
	}

	/**
	 * Gets the token balance of an SPL Token account.
	 */
	async getTokenAccountBalance(pubkey: PublicKey): Promise<TokenBalance> {
		return await this.queryClient.getTokenAccountBalance(pubkey);
	}

	/**
	 * Gets registered REX requests for a creator.
	 */
	async getRexRequests(
		creator: PublicKey,
		nonce: string | undefined,
	): Promise<RexInfoAndDuties[]> {
		return await this.queryClient.getRexRequests(creator, nonce);
	}

	/**
	 * Gets missed REX duty proposal rounds for a specific REX request.
	 */
	async getRexMissedDuties(
		creator: PublicKey,
		nonce: string,
	): Promise<bigint[]> {
		return await this.queryClient.getRexMissedDuties(creator, nonce);
	}

	/**
	 * Gets information about all known cluster nodes.
	 */
	async getClusterNodes(): Promise<ClusterNodeInfo[]> {
		return await this.queryClient.getClusterNodes();
	}

	/**
	 * Gets the list of validator indices this node is connected to.
	 */
	async getConnectedValidators(): Promise<number[]> {
		return await this.queryClient.getConnectedValidators();
	}

	/**
	 * Calls an arbitrary RPC method with a JSON string body.
	 * Utility method for methods not yet in the generated interface.
	 */
	async callWithJson(method: string, params: string): Promise<string> {
		return await this.queryClient.callWithJson(method, params);
	}
}
