/**
 * Error codes for transaction operations.
 */
export enum TransactionErrorCode {
	// Building errors
	INVALID_INSTRUCTION = "INVALID_INSTRUCTION",
	INVALID_ACCOUNT_META = "INVALID_ACCOUNT_META",
	NO_INSTRUCTIONS = "NO_INSTRUCTIONS",
	DUPLICATE_ACCOUNT = "DUPLICATE_ACCOUNT",

	// Signing errors
	MISSING_SIGNATURE = "MISSING_SIGNATURE",
	INVALID_SIGNATURE = "INVALID_SIGNATURE",
	SIGNATURE_OUT_OF_BOUNDS = "SIGNATURE_OUT_OF_BOUNDS",
	SIGNER_NOT_FOUND = "SIGNER_NOT_FOUND",
	ALREADY_SIGNED = "ALREADY_SIGNED",

	// Serialization errors
	INVALID_MESSAGE_FORMAT = "INVALID_MESSAGE_FORMAT",
	INSUFFICIENT_DATA = "INSUFFICIENT_DATA",
	SERIALIZATION_FAILED = "SERIALIZATION_FAILED",

	// Simulation errors
	SIMULATION_FAILED = "SIMULATION_FAILED",
	INSUFFICIENT_FUNDS = "INSUFFICIENT_FUNDS",
	BLOCKHASH_EXPIRED = "BLOCKHASH_EXPIRED",
}

/**
 * Error class for transaction operations with structured error information.
 */
export class TransactionError extends Error {
	constructor(
		public readonly code: TransactionErrorCode,
		message: string,
		public readonly details?: Record<string, unknown>,
	) {
		super(message);
		this.name = "TransactionError";
	}

	static noInstructions(): TransactionError {
		return new TransactionError(
			TransactionErrorCode.NO_INSTRUCTIONS,
			"Transaction must contain at least one instruction. Use addInstruction() to add instructions.",
		);
	}

	static signerNotFound(pubkey: string): TransactionError {
		return new TransactionError(
			TransactionErrorCode.SIGNER_NOT_FOUND,
			`Public key ${pubkey} is not a required signer for this transaction. Check that the account is marked as a signer in the instruction.`,
			{ pubkey },
		);
	}

	static missingSignature(index: number, pubkey: string): TransactionError {
		return new TransactionError(
			TransactionErrorCode.MISSING_SIGNATURE,
			`Missing signature for signer ${index} (${pubkey}). Transaction requires ${index + 1} signatures.`,
			{ index, pubkey },
		);
	}

	static simulationFailed(logs: string[], error: string): TransactionError {
		return new TransactionError(
			TransactionErrorCode.SIMULATION_FAILED,
			`Transaction simulation failed: ${error}`,
			{ logs, error },
		);
	}

	static insufficientFunds(
		required: bigint,
		available: bigint,
	): TransactionError {
		return new TransactionError(
			TransactionErrorCode.INSUFFICIENT_FUNDS,
			`Insufficient funds: need ${required}, have ${available}`,
			{ required: required.toString(), available: available.toString() },
		);
	}

	toJSON(): {
		code: TransactionErrorCode;
		message: string;
		details?: Record<string, unknown>;
	} {
		return {
			code: this.code,
			message: this.message,
			details: this.details,
		};
	}
}
