/**
 * Compact-u16 encoding for efficient variable-length integer serialization.
 *
 * Uses 1-3 bytes depending on value size:
 * - 0-127: 1 byte (7 bits)
 * - 128-16,383: 2 bytes (14 bits)
 * - 16,384-65,535: 3 bytes (16 bits)
 *
 * This encoding saves space for small numbers while supporting the full u16 range.
 */
import {
	TransactionError,
	TransactionErrorCode,
} from "../transaction/index.js";

/**
 * Serializes a u16 value into compact encoding.
 *
 * @param buffer - Output buffer to append bytes to
 * @param value - Value to encode (0-65535)
 * @throws {TransactionError} If value is out of range
 */
export function serializeCompactU16(buffer: number[], value: number): void {
	if (value < 0 || value > 0xffff) {
		throw new TransactionError(
			TransactionErrorCode.SERIALIZATION_FAILED,
			`Value out of range for compact-u16: ${value}`,
		);
	}

	// Single byte (0-127)
	if (value <= 0x7f) {
		buffer.push(value);
		return;
	}

	// Two bytes (128-16383)
	if (value <= 0x3fff) {
		buffer.push((value & 0x7f) | 0x80);
		buffer.push((value >> 7) & 0x7f);
		return;
	}

	// Three bytes (16384-65535)
	buffer.push((value & 0x7f) | 0x80);
	buffer.push(((value >> 7) & 0x7f) | 0x80);
	buffer.push((value >> 14) & 0xff);
}

/**
 * Deserializes a compact-u16 value from bytes.
 *
 * @param data - Input byte array
 * @param currentCursor - Starting position in the array
 * @returns Tuple of [decoded value, new cursor position]
 * @throws {TransactionError} If data is insufficient or malformed
 */
export function deserializeCompactU16(
	data: Uint8Array,
	currentCursor: number,
): [number, number] {
	let cursor = currentCursor;
	if (cursor >= data.length) {
		throw new TransactionError(
			TransactionErrorCode.INSUFFICIENT_DATA,
			"Insufficient data for compact-u16",
		);
	}

	const firstByte = data[cursor++];

	// Single byte encoding (0-127)
	if ((firstByte & 0x80) === 0) {
		return [firstByte, cursor];
	}

	// Multi-byte encoding
	if (cursor >= data.length) {
		throw new TransactionError(
			TransactionErrorCode.INSUFFICIENT_DATA,
			"Incomplete compact-u16 encoding",
		);
	}

	const secondByte = data[cursor++];

	// Two-byte encoding (128-16383)
	if ((secondByte & 0x80) === 0) {
		return [(firstByte & 0x7f) | (secondByte << 7), cursor];
	}

	// Three-byte encoding (16384-65535)
	if (cursor >= data.length) {
		throw new TransactionError(
			TransactionErrorCode.INSUFFICIENT_DATA,
			"Incomplete compact-u16 encoding",
		);
	}

	const thirdByte = data[cursor++];
	const value =
		(firstByte & 0x7f) | ((secondByte & 0x7f) << 7) | (thirdByte << 14);

	return [value, cursor];
}

/**
 * Writes a compact-u16 value directly to a buffer (zero-copy).
 *
 * Optimized version for in-place writing without intermediate allocations.
 *
 * @param buffer - Target buffer
 * @param offset - Starting position to write at
 * @param value - Value to encode (0-127 only, uses 1-2 bytes)
 * @returns New offset after writing
 */
export function writeCompactU16(
	buffer: Uint8Array,
	offset: number,
	value: number,
): number {
	if (value < 0x80) {
		buffer[offset] = value;
		return offset + 1;
	}
	buffer[offset] = (value & 0x7f) | 0x80;
	buffer[offset + 1] = value >> 7;
	return offset + 2;
}
