/**
 * Error codes for RPC operations, categorized by type.
 */
export enum RpcErrorCode {
	// Network errors (retryable)
	REQUEST_TIMEOUT = "REQUEST_TIMEOUT",
	NETWORK_ERROR = "NETWORK_ERROR",
	CONNECTION_REFUSED = "CONNECTION_REFUSED",
	INVALID_NETWORK = "INVALID_NETWORK",

	// RPC protocol errors
	INVALID_RESPONSE = "INVALID_RESPONSE",
	PARSE_ERROR = "PARSE_ERROR",
	INVALID_REQUEST = "INVALID_REQUEST",
	METHOD_NOT_FOUND = "METHOD_NOT_FOUND",
	INVALID_PARAMS = "INVALID_PARAMS",
	INTERNAL_ERROR = "INTERNAL_ERROR",

	// Transaction errors
	TRANSACTION_REJECTED = "TRANSACTION_REJECTED",
	INSUFFICIENT_FUNDS = "INSUFFICIENT_FUNDS",
	TRANSACTION_CONFIRMATION_TIMEOUT = "TRANSACTION_CONFIRMATION_TIMEOUT",

	// Resource errors
	ACCOUNT_NOT_FOUND = "ACCOUNT_NOT_FOUND",

	// Rate limiting (retryable after delay)
	RATE_LIMIT_EXCEEDED = "RATE_LIMIT_EXCEEDED",

	// Node health
	NODE_UNHEALTHY = "NODE_UNHEALTHY",
}

/**
 * Detailed error context for debugging and error handling.
 */
interface RpcErrorDetails {
	method?: string;
	params?: unknown;
	requestId?: number;
	url?: string;
	httpStatus?: number;
	rpcCode?: number;
	timeout?: number;
	attempts?: number;
	[key: string]: unknown;
}

/**
 * Error class for RPC operations with structured error information.
 *
 * Provides actionable error messages and indicates whether errors are retryable.
 */
export class RpcError extends Error {
	public readonly code: RpcErrorCode;
	public readonly details: RpcErrorDetails;
	public readonly retryable: boolean;

	constructor(
		code: RpcErrorCode,
		message: string,
		details: RpcErrorDetails = {},
		retryable = false,
	) {
		super(message);
		this.name = "RpcError";
		this.code = code;
		this.details = details;
		this.retryable = retryable;
	}

	static requestTimeout(timeoutMs: number, details: RpcErrorDetails): RpcError {
		return new RpcError(
			RpcErrorCode.REQUEST_TIMEOUT,
			`RPC request timed out after ${timeoutMs}ms. The node may be slow or unreachable.`,
			{ ...details, timeout: timeoutMs },
			true, // Retryable
		);
	}

	static networkError(message: string, details: RpcErrorDetails): RpcError {
		return new RpcError(
			RpcErrorCode.NETWORK_ERROR,
			`Network error: ${message}. Check your internet connection and node URL.`,
			details,
			true, // Retryable
		);
	}

	static invalidResponse(details: RpcErrorDetails): RpcError {
		return new RpcError(
			RpcErrorCode.INVALID_RESPONSE,
			"Received invalid response from RPC node. The response format is unexpected.",
			details,
			false,
		);
	}

	static accountNotFound(pubkey: string): RpcError {
		return new RpcError(
			RpcErrorCode.ACCOUNT_NOT_FOUND,
			`Account ${pubkey} not found on chain. It may not exist or has zero balance.`,
			{ pubkey },
			false,
		);
	}

	static rateLimitExceeded(details: RpcErrorDetails): RpcError {
		return new RpcError(
			RpcErrorCode.RATE_LIMIT_EXCEEDED,
			"Rate limit exceeded. Too many requests to the RPC endpoint. Try again later or use a different endpoint.",
			details,
			true, // Can retry after delay
		);
	}

	static fromRpcCode(
		rpcCode: number,
		message: string,
		details: RpcErrorDetails,
	): RpcError {
		// Map JSON-RPC error codes to our error codes
		const codeMap: Record<number, RpcErrorCode> = {
			[-32700]: RpcErrorCode.PARSE_ERROR,
			[-32600]: RpcErrorCode.INVALID_REQUEST,
			[-32601]: RpcErrorCode.METHOD_NOT_FOUND,
			[-32602]: RpcErrorCode.INVALID_PARAMS,
			[-32603]: RpcErrorCode.INTERNAL_ERROR,
			[429]: RpcErrorCode.RATE_LIMIT_EXCEEDED,
		};

		const code = codeMap[rpcCode] || RpcErrorCode.INTERNAL_ERROR;
		const retryable = rpcCode === 429 || rpcCode === -32603;

		return new RpcError(code, message, { ...details, rpcCode }, retryable);
	}

	toJSON(): {
		code: RpcErrorCode;
		message: string;
		details?: Record<string, unknown>;
		retryable: boolean;
	} {
		return {
			code: this.code,
			message: this.message,
			details: this.details,
			retryable: this.retryable,
		};
	}
}
