import { hmac } from "@noble/hashes/hmac";
import { sha512 } from "@noble/hashes/sha2";
import * as bip39 from "@scure/bip39";
import { wordlist } from "@scure/bip39/wordlists/english.js";
import { BASE_DERIVATION_PATH } from "../constants";
import { CryptoError, CryptoErrorCode } from "./errors";
import { Keypair } from "./keypair";

export type MnemonicStrength = 128 | 256;

interface HDKeyNode {
	privateKey: Uint8Array;
	chainCode: Uint8Array;
}

/**
 * Represents a validated BIP39 mnemonic phrase with SLIP-0010 Ed25519 hierarchical key derivation.
 *
 * Implements the SLIP-0010 standard for Ed25519 key derivation, ensuring compatibility
 * with other implementations (e.g., Rust CDK). The default derivation path uses coin type
 * 756 (R=7, L=5, O=6 on telephone keypad).
 *
 * @example
 * ```typescript
 * // Generate new mnemonic (12 or 24 words)
 * const mnemonic = Mnemonic.generate(128); // 12 words
 *
 * // Restore from existing phrase
 * const restored = Mnemonic.fromPhrase("word1 word2 ...");
 *
 * // Derive keypairs at specific account indices
 * const keypair0 = await mnemonic.toKeypair(0); // m/44'/756'/0'/0'
 * const keypair1 = await mnemonic.toKeypair(1); // m/44'/756'/1'/0'
 *
 * // With custom passphrase (BIP39 extension)
 * const secure = await mnemonic.toKeypair(0, {
 *   passphrase: "my-secret"
 * });
 * ```
 *
 * @see {@link https://github.com/satoshilabs/slips/blob/master/slip-0010.md SLIP-0010 Specification}
 */
export class Mnemonic {
	private readonly phrase: string;

	private constructor(phrase: string) {
		if (!bip39.validateMnemonic(phrase, wordlist)) {
			throw CryptoError.invalidMnemonic("Invalid BIP39 mnemonic phrase");
		}
		this.phrase = phrase;
	}

	/**
	 * Generates a new random BIP39 mnemonic phrase.
	 *
	 * @param strength - Entropy strength (128 = 12 words, 256 = 24 words). Default: 128
	 * @returns Validated Mnemonic instance
	 */
	static generate(strength: MnemonicStrength = 128): Mnemonic {
		const phrase = bip39.generateMnemonic(wordlist, strength);
		return new Mnemonic(phrase);
	}

	/**
	 * Creates a Mnemonic from an existing phrase.
	 *
	 * @param phrase - BIP39 mnemonic phrase (12 or 24 space-separated words)
	 * @returns Validated Mnemonic instance
	 * @throws {CryptoError} If phrase is invalid (wrong words or checksum)
	 */
	static fromPhrase(phrase: string): Mnemonic {
		return new Mnemonic(phrase);
	}

	/**
	 * Validates a phrase without creating an instance.
	 *
	 * Checks both word validity and BIP39 checksum.
	 *
	 * @param phrase - Mnemonic phrase to validate
	 * @returns true if phrase is valid
	 */
	static isValid(phrase: string): boolean {
		return bip39.validateMnemonic(phrase, wordlist);
	}

	private getMasterKeyFromSeed(seed: Uint8Array): HDKeyNode {
		const seedKey = new TextEncoder().encode("ed25519 seed");
		const digest = hmac(sha512, seedKey, seed);

		return {
			privateKey: digest.slice(0, 32),
			chainCode: digest.slice(32, 64),
		};
	}

	private deriveChildKey(parentKey: HDKeyNode, index: number): HDKeyNode {
		const hardenedIndex = index | 0x80000000;
		const data = new Uint8Array(1 + 32 + 4);
		data[0] = 0x00;
		data.set(parentKey.privateKey, 1);

		const view = new DataView(data.buffer);
		view.setUint32(33, hardenedIndex, false);

		const digest = hmac(sha512, parentKey.chainCode, data);

		return {
			privateKey: digest.slice(0, 32),
			chainCode: digest.slice(32, 64),
		};
	}

	private derivePath(path: string, seed: Uint8Array): HDKeyNode {
		if (!path.startsWith("m/")) {
			throw new CryptoError(
				CryptoErrorCode.KEY_DERIVATION_FAILED,
				"Derivation path must start with 'm/'",
			);
		}

		let node = this.getMasterKeyFromSeed(seed);
		const segments = path.slice(2).split("/");

		for (const segment of segments) {
			if (!segment) continue;

			const index = segment.endsWith("'")
				? Number.parseInt(segment.slice(0, -1), 10)
				: Number.parseInt(segment, 10);

			if (Number.isNaN(index) || index < 0) {
				throw new CryptoError(
					CryptoErrorCode.KEY_DERIVATION_FAILED,
					`Invalid path segment: ${segment}`,
				);
			}

			node = this.deriveChildKey(node, index);
		}

		return node;
	}

	/**
	 * Derives a keypair at a specific account index.
	 *
	 * Uses SLIP-0010 Ed25519 derivation with the default path:
	 * `m/44'/756'/{accountIndex}'/0'`
	 *
	 * Coin type 756 follows the telephone keypad convention (R=7, L=5, O=6).
	 *
	 * @param accountIndex - Account index to derive (default: 0)
	 * @param options - Derivation options
	 * @param options.passphrase - Optional BIP39 passphrase for additional security
	 * @param options.baseDerivationPath - Base path (default: "m/44'/756'")
	 * @returns Keypair for the derived account
	 */
	async toKeypair(
		accountIndex = 0,
		options?: {
			passphrase?: string;
			baseDerivationPath?: string;
		},
	): Promise<Keypair> {
		if (accountIndex < 0 || !Number.isInteger(accountIndex)) {
			throw new CryptoError(
				CryptoErrorCode.KEY_DERIVATION_FAILED,
				"Account index must be a non-negative integer",
				{ accountIndex },
			);
		}

		const { passphrase = "", baseDerivationPath = BASE_DERIVATION_PATH } =
			options ?? {};

		try {
			const fullPath = this.buildFullPath(baseDerivationPath, accountIndex);
			const seed = await bip39.mnemonicToSeed(this.phrase, passphrase);
			const derivedNode = this.derivePath(fullPath, seed);

			return Keypair.fromSecretKey(derivedNode.privateKey);
		} catch (error) {
			if (error instanceof CryptoError) {
				throw error;
			}
			throw CryptoError.keyDerivationFailed(
				baseDerivationPath,
				error instanceof Error ? error : undefined,
			);
		}
	}

	/**
	 * Derives a keypair using an explicit full derivation path.
	 *
	 * @param fullPath - Complete derivation path (e.g., "m/44'/756'/0'/0'")
	 * @param passphrase - Optional BIP39 passphrase
	 */
	async toKeypairWithPath(fullPath: string, passphrase = ""): Promise<Keypair> {
		try {
			const seed = await bip39.mnemonicToSeed(this.phrase, passphrase);
			const derivedNode = this.derivePath(fullPath, seed);
			return Keypair.fromSecretKey(derivedNode.privateKey);
		} catch (error) {
			if (error instanceof CryptoError) {
				throw error;
			}
			throw CryptoError.keyDerivationFailed(
				fullPath,
				error instanceof Error ? error : undefined,
			);
		}
	}

	/**
	 * Derives multiple keypairs sequentially from this mnemonic.
	 *
	 * @param count - Number of keypairs to derive
	 * @param startIndex - Starting account index (default: 0)
	 * @param options - Derivation options (passphrase and path)
	 */
	async deriveKeypairs(
		count: number,
		startIndex = 0,
		options?: {
			passphrase?: string;
			baseDerivationPath?: string;
		},
	): Promise<Keypair[]> {
		if (count <= 0 || !Number.isInteger(count)) {
			throw new CryptoError(
				CryptoErrorCode.KEY_DERIVATION_FAILED,
				"Count must be a positive integer",
				{ count },
			);
		}

		const keypairs: Keypair[] = [];
		for (let i = 0; i < count; i++) {
			const keypair = await this.toKeypair(startIndex + i, options);
			keypairs.push(keypair);
		}

		return keypairs;
	}

	/**
	 * Converts the mnemonic to a BIP39 seed.
	 *
	 * @param passphrase - Optional BIP39 passphrase for additional security
	 * @returns 64-byte seed
	 */
	async toSeed(passphrase = ""): Promise<Uint8Array> {
		return bip39.mnemonicToSeed(this.phrase, passphrase);
	}

	/**
	 * Returns the mnemonic phrase as a string.
	 */
	toString(): string {
		return this.phrase;
	}

	/**
	 * Returns the individual words of the mnemonic.
	 */
	getWords(): string[] {
		return this.phrase.split(" ");
	}

	/**
	 * Returns the word count (12 or 24).
	 */
	getWordCount(): 12 | 24 {
		const count = this.getWords().length;
		return count === 24 ? 24 : 12;
	}

	/**
	 * Returns the entropy strength (128 or 256 bits).
	 */
	getStrength(): MnemonicStrength {
		return this.getWordCount() === 12 ? 128 : 256;
	}

	/**
	 * Checks equality with another mnemonic using constant-time comparison.
	 */
	equals(other: Mnemonic): boolean {
		if (this.phrase.length !== other.phrase.length) return false;
		let result = 0;
		for (let i = 0; i < this.phrase.length; i++) {
			result |= this.phrase.charCodeAt(i) ^ other.phrase.charCodeAt(i);
		}
		return result === 0;
	}

	/**
	 * JSON serialization (returns the mnemonic phrase).
	 */
	toJSON(): string {
		return this.phrase;
	}

	private buildFullPath(
		baseDerivationPath: string,
		accountIndex: number,
	): string {
		const cleanBasePath = baseDerivationPath.replace(/\/$/, "");

		if (!cleanBasePath.startsWith("m/")) {
			throw new CryptoError(
				CryptoErrorCode.KEY_DERIVATION_FAILED,
				"Derivation path must start with 'm/'",
			);
		}

		return `${cleanBasePath}/${accountIndex}'/0'`;
	}
}
