/**
 * Bincode serialization writer
 *
 * Matches Rust's bincode crate with default configuration:
 * - Little-endian byte order
 * - Fixed-size integer encoding (no varint)
 * - u64 length prefixes for dynamic collections
 * - u32 enum variant indices
 */
export class BincodeWriter {
	private buffer: Uint8Array;
	private offset: number;
	private view: DataView;

	constructor(initialCapacity = 256) {
		this.buffer = new Uint8Array(initialCapacity);
		this.view = new DataView(this.buffer.buffer);
		this.offset = 0;
	}

	// ========== Primitive Types ==========

	writeU8(value: number): this {
		if (value < 0 || value > 0xff) {
			throw new Error(`u8 value out of range: ${value}`);
		}
		this.ensureCapacity(1);
		this.buffer[this.offset++] = value;
		return this;
	}

	writeU16(value: number): this {
		if (value < 0 || value > 0xffff) {
			throw new Error(`u16 value out of range: ${value}`);
		}
		this.ensureCapacity(2);
		this.view.setUint16(this.offset, value, true);
		this.offset += 2;
		return this;
	}

	writeU32(value: number): this {
		if (value < 0 || value > 0xffffffff) {
			throw new Error(`u32 value out of range: ${value}`);
		}
		this.ensureCapacity(4);
		this.view.setUint32(this.offset, value, true);
		this.offset += 4;
		return this;
	}

	writeU64(value: bigint | number): this {
		const val = BigInt(value);
		if (val < 0n || val > 0xffff_ffff_ffff_ffffn) {
			throw new Error(`u64 value out of range: ${val}`);
		}
		this.ensureCapacity(8);
		// Write as two u32s for better performance
		this.view.setUint32(this.offset, Number(val & 0xffff_ffffn), true);
		this.view.setUint32(
			this.offset + 4,
			Number((val >> 32n) & 0xffff_ffffn),
			true,
		);
		this.offset += 8;
		return this;
	}

	writeU128(value: bigint): this {
		if (value < 0n || value > (1n << 128n) - 1n) {
			throw new Error(`u128 value out of range: ${value}`);
		}
		this.writeU64(value & ((1n << 64n) - 1n));
		this.writeU64(value >> 64n);
		return this;
	}

	writeI8(value: number): this {
		if (value < -128 || value > 127) {
			throw new Error(`i8 value out of range: ${value}`);
		}
		this.ensureCapacity(1);
		this.view.setInt8(this.offset, value);
		this.offset += 1;
		return this;
	}

	writeI16(value: number): this {
		if (value < -32768 || value > 32767) {
			throw new Error(`i16 value out of range: ${value}`);
		}
		this.ensureCapacity(2);
		this.view.setInt16(this.offset, value, true);
		this.offset += 2;
		return this;
	}

	writeI32(value: number): this {
		if (value < -2147483648 || value > 2147483647) {
			throw new Error(`i32 value out of range: ${value}`);
		}
		this.ensureCapacity(4);
		this.view.setInt32(this.offset, value, true);
		this.offset += 4;
		return this;
	}

	writeI64(value: bigint): this {
		const min = -(1n << 63n);
		const max = (1n << 63n) - 1n;
		if (value < min || value > max) {
			throw new Error(`i64 value out of range: ${value}`);
		}
		this.ensureCapacity(8);
		// For signed integers, we write the bit pattern directly
		// JavaScript's BigInt handles two's complement correctly
		const unsigned = value < 0n ? value + (1n << 64n) : value;
		this.view.setUint32(this.offset, Number(unsigned & 0xffff_ffffn), true);
		this.view.setUint32(
			this.offset + 4,
			Number((unsigned >> 32n) & 0xffff_ffffn),
			true,
		);
		this.offset += 8;
		return this;
	}

	writeI128(value: bigint): this {
		const min = -(1n << 127n);
		const max = (1n << 127n) - 1n;
		if (value < min || value > max) {
			throw new Error(`i128 value out of range: ${value}`);
		}
		// Convert to unsigned representation for writing
		const unsigned = value < 0n ? value + (1n << 128n) : value;
		this.writeU64(unsigned & ((1n << 64n) - 1n));
		this.writeU64(unsigned >> 64n);
		return this;
	}

	writeF32(value: number): this {
		this.ensureCapacity(4);
		this.view.setFloat32(this.offset, value, true);
		this.offset += 4;
		return this;
	}

	writeF64(value: number): this {
		this.ensureCapacity(8);
		this.view.setFloat64(this.offset, value, true);
		this.offset += 8;
		return this;
	}

	writeBool(value: boolean): this {
		this.ensureCapacity(1);
		this.buffer[this.offset++] = value ? 1 : 0;
		return this;
	}

	// ========== Compound Types ==========

	writeBytes(bytes: Uint8Array): this {
		this.ensureCapacity(bytes.length);
		this.buffer.set(bytes, this.offset);
		this.offset += bytes.length;
		return this;
	}

	writeFixedArray(bytes: Uint8Array, expectedLength?: number): this {
		if (expectedLength !== undefined && bytes.length !== expectedLength) {
			throw new Error(
				`Fixed array length mismatch: expected ${expectedLength}, got ${bytes.length}`,
			);
		}
		return this.writeBytes(bytes);
	}

	writeVecBytes(bytes: Uint8Array): this {
		this.writeU64(BigInt(bytes.length));
		return this.writeBytes(bytes);
	}

	writeString(str: string): this {
		const bytes = new TextEncoder().encode(str);
		return this.writeVecBytes(bytes);
	}

	writeVariant(index: number): this {
		return this.writeU32(index);
	}

	writeOption<T>(
		value: T | null | undefined,
		writeValue: (writer: BincodeWriter, val: T) => void,
	): this {
		if (value === null || value === undefined) {
			this.writeU8(0);
		} else {
			this.writeU8(1);
			writeValue(this, value);
		}
		return this;
	}

	writeVec<T>(
		items: T[],
		writeItem: (writer: BincodeWriter, item: T) => void,
	): this {
		this.writeU64(BigInt(items.length));
		for (const item of items) {
			writeItem(this, item);
		}
		return this;
	}

	/**
	 * Write a tuple (fixed-size heterogeneous collection)
	 */
	writeTuple<T extends unknown[]>(
		items: T,
		writers: { [K in keyof T]: (writer: BincodeWriter, val: T[K]) => void },
	): this {
		for (let i = 0; i < items.length; i++) {
			(writers[i] as (writer: BincodeWriter, val: unknown) => void)(
				this,
				items[i],
			);
		}
		return this;
	}

	writeMap<K, V>(
		map: Map<K, V>,
		writeKey: (writer: BincodeWriter, key: K) => void,
		writeValue: (writer: BincodeWriter, value: V) => void,
	): this {
		this.writeU64(BigInt(map.size));
		for (const [key, value] of map) {
			writeKey(this, key);
			writeValue(this, value);
		}
		return this;
	}

	// ========== Output ==========

	toBytes(): Uint8Array {
		return this.buffer.slice(0, this.offset);
	}

	/**
	 * Get a view of the written bytes WITHOUT copying.
	 *
	 * ⚠️ WARNING: This returns a view into the internal buffer.
	 * The view becomes INVALID if:
	 * - The writer continues writing (may trigger resize)
	 * - The writer is cleared via clear()
	 *
	 * Use toBytes() for a safe copy, or use this only for immediate
	 * read-only access when performance is critical.
	 */
	toView(): Uint8Array {
		return this.buffer.subarray(0, this.offset);
	}

	length(): number {
		return this.offset;
	}

	clear(): this {
		this.offset = 0;
		return this;
	}

	/**
	 * Reserve additional capacity
	 */
	reserve(additionalBytes: number): this {
		this.ensureCapacity(additionalBytes);
		return this;
	}

	// ========== Internal ==========

	private ensureCapacity(needed: number): void {
		const required = this.offset + needed;
		if (required <= this.buffer.length) {
			return;
		}
		// Grow by at least 2x or to required size
		let newCapacity = this.buffer.length * 2;
		while (newCapacity < required) {
			newCapacity *= 2;
		}
		const newBuffer = new Uint8Array(newCapacity);
		newBuffer.set(this.buffer);
		this.buffer = newBuffer;
		this.view = new DataView(this.buffer.buffer);
	}
}
