import { BincodeReader } from "./reader";
import { BincodeWriter } from "./writer";

/**
 * Type definitions for bincode schemas
 *
 * IMPORTANT: For structs and enums, field/variant order MUST match Rust definition order.
 * Use arrays of tuples instead of objects to guarantee order preservation.
 */
export type BincodeSchema =
	| { type: "u8" }
	| { type: "u16" }
	| { type: "u32" }
	| { type: "u64" }
	| { type: "u128" }
	| { type: "i8" }
	| { type: "i16" }
	| { type: "i32" }
	| { type: "i64" }
	| { type: "i128" }
	| { type: "f32" }
	| { type: "f64" }
	| { type: "bool" }
	| { type: "string" }
	| { type: "bytes" }
	| { type: "unit" } // Rust's () type - zero size
	| { type: "fixedArray"; length: number }
	| { type: "vec"; element: BincodeSchema }
	| { type: "option"; inner: BincodeSchema }
	| { type: "tuple"; elements: BincodeSchema[] }
	| { type: "struct"; fields: StructField[] } // Ordered array, not object!
	| { type: "enum"; variants: EnumVariant[] } // Ordered array, not object!
	| { type: "map"; key: BincodeSchema; value: BincodeSchema }
	| { type: "pubkey" }; // 32-byte public key (Solana specific)

/**
 * Struct field definition - order matters!
 */
export interface StructField {
	name: string;
	schema: BincodeSchema;
}

/**
 * Enum variant definition - order matters!
 */
export interface EnumVariant {
	name: string;
	schema: BincodeSchema | null; // null for unit variants
}

// ========== Schema Builder Helpers ==========

export const Schema = {
	u8: (): BincodeSchema => ({ type: "u8" }),
	u16: (): BincodeSchema => ({ type: "u16" }),
	u32: (): BincodeSchema => ({ type: "u32" }),
	u64: (): BincodeSchema => ({ type: "u64" }),
	u128: (): BincodeSchema => ({ type: "u128" }),
	i8: (): BincodeSchema => ({ type: "i8" }),
	i16: (): BincodeSchema => ({ type: "i16" }),
	i32: (): BincodeSchema => ({ type: "i32" }),
	i64: (): BincodeSchema => ({ type: "i64" }),
	i128: (): BincodeSchema => ({ type: "i128" }),
	f32: (): BincodeSchema => ({ type: "f32" }),
	f64: (): BincodeSchema => ({ type: "f64" }),
	bool: (): BincodeSchema => ({ type: "bool" }),
	string: (): BincodeSchema => ({ type: "string" }),
	bytes: (): BincodeSchema => ({ type: "bytes" }),
	unit: (): BincodeSchema => ({ type: "unit" }),

	fixedArray: (length: number): BincodeSchema => ({
		type: "fixedArray",
		length,
	}),

	vec: (element: BincodeSchema): BincodeSchema => ({
		type: "vec",
		element,
	}),

	option: (inner: BincodeSchema): BincodeSchema => ({
		type: "option",
		inner,
	}),

	tuple: (...elements: BincodeSchema[]): BincodeSchema => ({
		type: "tuple",
		elements,
	}),

	/**
	 * Define a struct with ordered fields
	 * @example
	 * Schema.struct([
	 *   ["id", Schema.u64()],
	 *   ["name", Schema.string()],
	 *   ["active", Schema.bool()],
	 * ])
	 */
	struct: (fields: [string, BincodeSchema][]): BincodeSchema => ({
		type: "struct",
		fields: fields.map(([name, schema]) => ({ name, schema })),
	}),

	/**
	 * Define an enum with ordered variants
	 * @example
	 * Schema.enum([
	 *   ["None", null],
	 *   ["Some", Schema.u64()],
	 *   ["Error", Schema.string()],
	 * ])
	 */
	enum: (variants: [string, BincodeSchema | null][]): BincodeSchema => ({
		type: "enum",
		variants: variants.map(([name, schema]) => ({ name, schema })),
	}),

	map: (key: BincodeSchema, value: BincodeSchema): BincodeSchema => ({
		type: "map",
		key,
		value,
	}),

	pubkey: (): BincodeSchema => ({ type: "pubkey" }),
} as const;

// ========== Serialization ==========

/**
 * Serialize a value according to a schema
 */
export function serialize(schema: BincodeSchema, value: unknown): Uint8Array {
	const writer = new BincodeWriter();
	writeValue(writer, schema, value);
	return writer.toBytes();
}

/**
 * Deserialize bytes according to a schema
 */
export function deserialize<T>(schema: BincodeSchema, data: Uint8Array): T {
	const reader = new BincodeReader(data);
	const result = readValue(reader, schema) as T;

	// Verify all bytes were consumed (optional strict mode)
	if (!reader.isExhausted()) {
		console.warn(
			`Bincode deserialize: ${reader.remaining()} bytes remaining after parsing`,
		);
	}

	return result;
}

/**
 * Deserialize bytes with strict validation
 */
export function deserializeStrict<T>(
	schema: BincodeSchema,
	data: Uint8Array,
): T {
	const reader = new BincodeReader(data);
	const result = readValue(reader, schema) as T;

	if (!reader.isExhausted()) {
		throw new Error(
			`Unexpected data: ${reader.remaining()} bytes remaining after parsing`,
		);
	}

	return result;
}

function writeValue(
	writer: BincodeWriter,
	schema: BincodeSchema,
	value: unknown,
): void {
	switch (schema.type) {
		case "u8":
			writer.writeU8(value as number);
			break;
		case "u16":
			writer.writeU16(value as number);
			break;
		case "u32":
			writer.writeU32(value as number);
			break;
		case "u64":
			writer.writeU64(value as bigint);
			break;
		case "u128":
			writer.writeU128(value as bigint);
			break;
		case "i8":
			writer.writeI8(value as number);
			break;
		case "i16":
			writer.writeI16(value as number);
			break;
		case "i32":
			writer.writeI32(value as number);
			break;
		case "i64":
			writer.writeI64(value as bigint);
			break;
		case "i128":
			writer.writeI128(value as bigint);
			break;
		case "f32":
			writer.writeF32(value as number);
			break;
		case "f64":
			writer.writeF64(value as number);
			break;
		case "bool":
			writer.writeBool(value as boolean);
			break;
		case "string":
			writer.writeString(value as string);
			break;
		case "bytes":
			writer.writeVecBytes(value as Uint8Array);
			break;
		case "unit":
			// Nothing to write for unit type
			break;
		case "fixedArray": {
			const arr = value as Uint8Array;
			if (arr.length !== schema.length) {
				throw new Error(
					`Fixed array length mismatch: expected ${schema.length}, got ${arr.length}`,
				);
			}
			writer.writeFixedArray(arr);
			break;
		}
		case "pubkey": {
			const arr = value as Uint8Array;
			if (arr.length !== 32) {
				throw new Error(`Pubkey must be exactly 32 bytes, got ${arr.length}`);
			}
			writer.writeFixedArray(arr);
			break;
		}
		case "vec": {
			const arr = value as unknown[];
			writer.writeU64(BigInt(arr.length));
			for (const item of arr) {
				writeValue(writer, schema.element, item);
			}
			break;
		}
		case "option": {
			if (value === null || value === undefined) {
				writer.writeU8(0);
			} else {
				writer.writeU8(1);
				writeValue(writer, schema.inner, value);
			}
			break;
		}
		case "tuple": {
			const arr = value as unknown[];
			if (arr.length !== schema.elements.length) {
				throw new Error(
					`Tuple length mismatch: expected ${schema.elements.length}, got ${arr.length}`,
				);
			}
			for (let i = 0; i < schema.elements.length; i++) {
				writeValue(writer, schema.elements[i], arr[i]);
			}
			break;
		}
		case "struct": {
			const obj = value as Record<string, unknown>;
			for (const field of schema.fields) {
				if (!(field.name in obj)) {
					throw new Error(`Missing struct field: ${field.name}`);
				}
				writeValue(writer, field.schema, obj[field.name]);
			}
			break;
		}
		case "enum": {
			const enumValue = value as { variant: string; value?: unknown };
			const variantIndex = schema.variants.findIndex(
				(v) => v.name === enumValue.variant,
			);
			if (variantIndex === -1) {
				const validVariants = schema.variants.map((v) => v.name).join(", ");
				throw new Error(
					`Unknown variant: ${enumValue.variant}. Valid variants: ${validVariants}`,
				);
			}
			writer.writeVariant(variantIndex);
			const variantSchema = schema.variants[variantIndex].schema;
			if (variantSchema !== null) {
				writeValue(writer, variantSchema, enumValue.value);
			}
			break;
		}
		case "map": {
			const map = value as Map<unknown, unknown>;
			writer.writeU64(BigInt(map.size));
			for (const [k, v] of map) {
				writeValue(writer, schema.key, k);
				writeValue(writer, schema.value, v);
			}
			break;
		}
		default: {
			throw new Error(`Unknown schema type: ${JSON.stringify(schema)}`);
		}
	}
}

function readValue(reader: BincodeReader, schema: BincodeSchema): unknown {
	switch (schema.type) {
		case "u8":
			return reader.readU8();
		case "u16":
			return reader.readU16();
		case "u32":
			return reader.readU32();
		case "u64":
			return reader.readU64();
		case "u128":
			return reader.readU128();
		case "i8":
			return reader.readI8();
		case "i16":
			return reader.readI16();
		case "i32":
			return reader.readI32();
		case "i64":
			return reader.readI64();
		case "i128":
			return reader.readI128();
		case "f32":
			return reader.readF32();
		case "f64":
			return reader.readF64();
		case "bool":
			return reader.readBool();
		case "string":
			return reader.readString();
		case "bytes":
			return reader.readVecBytes();
		case "unit":
			return undefined;
		case "fixedArray":
			return reader.readFixedArray(schema.length);
		case "pubkey":
			return reader.readFixedArray(32);
		case "vec": {
			const lengthBigInt = reader.readU64();
			if (lengthBigInt > BigInt(Number.MAX_SAFE_INTEGER)) {
				throw new Error(
					`Vec length ${lengthBigInt} exceeds safe integer range`,
				);
			}
			const length = Number(lengthBigInt);
			const result: unknown[] = [];
			for (let i = 0; i < length; i++) {
				result.push(readValue(reader, schema.element));
			}
			return result;
		}
		case "option": {
			const hasValue = reader.readU8();
			if (hasValue === 0) return null;
			if (hasValue !== 1) {
				throw new Error(`Invalid option discriminant: ${hasValue}`);
			}
			return readValue(reader, schema.inner);
		}
		case "tuple": {
			const result: unknown[] = [];
			for (const elementSchema of schema.elements) {
				result.push(readValue(reader, elementSchema));
			}
			return result;
		}
		case "struct": {
			const result: Record<string, unknown> = {};
			for (const field of schema.fields) {
				result[field.name] = readValue(reader, field.schema);
			}
			return result;
		}
		case "enum": {
			const variantIndex = reader.readVariant();
			if (variantIndex >= schema.variants.length) {
				throw new Error(
					`Invalid variant index: ${variantIndex}, max: ${schema.variants.length - 1}`,
				);
			}
			const variant = schema.variants[variantIndex];
			if (variant.schema === null) {
				return { variant: variant.name };
			}
			return {
				variant: variant.name,
				value: readValue(reader, variant.schema),
			};
		}
		case "map": {
			const lengthBigInt = reader.readU64();
			if (lengthBigInt > BigInt(Number.MAX_SAFE_INTEGER)) {
				throw new Error(
					`Map length ${lengthBigInt} exceeds safe integer range`,
				);
			}
			const length = Number(lengthBigInt);
			const map = new Map<unknown, unknown>();
			for (let i = 0; i < length; i++) {
				const key = readValue(reader, schema.key);
				const value = readValue(reader, schema.value);
				map.set(key, value);
			}
			return map;
		}
		default: {
			// Exhaustive check - TypeScript will error if a case is missing
			const _exhaustive: never = schema;
			throw new Error(
				`Unknown schema type: ${(_exhaustive as BincodeSchema).type}`,
			);
		}
	}
}

// ========== Type Inference Helpers ==========

/**
 * Infer TypeScript type from schema (for documentation purposes)
 *
 * Usage:
 * const mySchema = Schema.struct([...]);
 * type MyType = InferSchema<typeof mySchema>;
 */
export type InferSchema<S extends BincodeSchema> = S extends { type: "u8" }
	? number
	: S extends { type: "u16" }
		? number
		: S extends { type: "u32" }
			? number
			: S extends { type: "u64" }
				? bigint
				: S extends { type: "u128" }
					? bigint
					: S extends { type: "i8" }
						? number
						: S extends { type: "i16" }
							? number
							: S extends { type: "i32" }
								? number
								: S extends { type: "i64" }
									? bigint
									: S extends { type: "i128" }
										? bigint
										: S extends { type: "f32" }
											? number
											: S extends { type: "f64" }
												? number
												: S extends { type: "bool" }
													? boolean
													: S extends { type: "string" }
														? string
														: S extends { type: "bytes" }
															? Uint8Array
															: S extends { type: "unit" }
																? undefined
																: S extends { type: "fixedArray" }
																	? Uint8Array
																	: S extends { type: "pubkey" }
																		? Uint8Array
																		: S extends {
																					type: "vec";
																					element: infer E;
																				}
																			? E extends BincodeSchema
																				? InferSchema<E>[]
																				: never
																			: S extends {
																						type: "option";
																						inner: infer I;
																					}
																				? I extends BincodeSchema
																					? InferSchema<I> | null
																					: never
																				: unknown;
