import { KeyringProvider as KeyringProviderBase } from "../generated/keyring-provider.js";
import type { Keyring } from "../generated/keyring.js";
import type { DerivedKeypairInfo, PublicKey } from "../generated/types.js";
import { Keypair } from "../crypto/keypair.js";
import { Mnemonic, type MnemonicStrength } from "../crypto/mnemonic.js";
import { RialoError, RialoErrorType } from "../error.js";
import { BASE_DERIVATION_PATH } from "../constants.js";
import { RialoKeyring } from "./keyring.js";
import { validateKeypairIndex } from "./validation.js";

interface StoredKeyring {
	keypairs: Map<number, Keypair>;
	derivationPaths: Map<number, string | undefined>;
	mnemonic: string | undefined;
	password: string;
}

/**
 * In-memory keyring provider for testing and ephemeral use.
 *
 * **Security note:** This provider stores keyrings, passwords, and mnemonic
 * phrases in plaintext memory. It is designed for development, testing, and
 * ephemeral use cases — NOT for production secret storage. Key material
 * persists in the JS heap until garbage collected. For production use,
 * implement a provider backed by encrypted storage or a hardware security module.
 *
 * Keyrings are stored in memory only — not persisted between restarts.
 * Implements the full keyring-provider contract from the WIT spec.
 */
export class InMemoryKeyringProvider extends KeyringProviderBase {
	private readonly keyrings = new Map<string, StoredKeyring>();

	private getStored(name: string): StoredKeyring {
		const stored = this.keyrings.get(name);
		if (!stored) {
			throw new RialoError(RialoErrorType.WALLET, `Keyring not found: ${name}`);
		}
		return stored;
	}

	private checkPassword(stored: StoredKeyring, password: string): void {
		if (stored.password !== password) {
			throw new RialoError(RialoErrorType.PASSWORD, "Invalid password");
		}
	}

	private buildKeyring(stored: StoredKeyring): RialoKeyring {
		const keypairsCopy = new Map<number, Keypair>();
		for (const [idx, kp] of stored.keypairs) {
			keypairsCopy.set(idx, Keypair.fromSecretKey(kp.secretKeyBytes()));
		}
		const pathsCopy = new Map(stored.derivationPaths);
		return new RialoKeyring(keypairsCopy, pathsCopy);
	}

	private toInfo(index: number, kp: Keypair, derivationPath: string | undefined): DerivedKeypairInfo {
		return {
			index,
			pubkey: kp.publicKey,
			pubkeyString: kp.publicKey.toString(),
			derivationPath,
		};
	}

	private nextIndex(stored: StoredKeyring): number {
		if (stored.keypairs.size === 0) return 0;
		return Math.max(...stored.keypairs.keys()) + 1;
	}

	async create(name: string, password: string): Promise<Keyring> {
		if (this.keyrings.has(name)) {
			throw new RialoError(RialoErrorType.WALLET, `Keyring already exists: ${name}`);
		}

		const kp = Keypair.generate();
		const keypairs = new Map<number, Keypair>([[0, kp]]);
		const derivationPaths = new Map<number, string | undefined>([[0, undefined]]);

		this.keyrings.set(name, { keypairs, derivationPaths, mnemonic: undefined, password });
		return this.buildKeyring(this.getStored(name));
	}

	async createWithMnemonic(
		name: string,
		strengthBits: number,
		password: string,
	): Promise<[Keyring, string]> {
		if (this.keyrings.has(name)) {
			throw new RialoError(RialoErrorType.WALLET, `Keyring already exists: ${name}`);
		}
		if (strengthBits !== 128 && strengthBits !== 256) {
			throw new RialoError(
				RialoErrorType.INVALID_INPUT,
				`Invalid mnemonic strength: ${strengthBits}. Must be 128 or 256.`,
			);
		}

		const mnemonic = Mnemonic.generate(strengthBits as MnemonicStrength);
		const kp = await mnemonic.toKeypair(0);
		const path = `${BASE_DERIVATION_PATH}0'/0'`;

		const keypairs = new Map<number, Keypair>([[0, kp]]);
		const derivationPaths = new Map<number, string | undefined>([[0, path]]);

		this.keyrings.set(name, {
			keypairs,
			derivationPaths,
			mnemonic: mnemonic.toString(),
			password,
		});

		return [this.buildKeyring(this.getStored(name)), mnemonic.toString()];
	}

	async recoverFromMnemonic(
		name: string,
		mnemonicPhrase: string,
		password: string,
	): Promise<Keyring> {
		if (this.keyrings.has(name)) {
			throw new RialoError(RialoErrorType.WALLET, `Keyring already exists: ${name}`);
		}
		if (!Mnemonic.isValid(mnemonicPhrase)) {
			throw new RialoError(RialoErrorType.INVALID_INPUT, "Invalid BIP39 mnemonic phrase");
		}

		const mnemonic = Mnemonic.fromPhrase(mnemonicPhrase);
		const kp = await mnemonic.toKeypair(0);
		const path = `${BASE_DERIVATION_PATH}0'/0'`;

		const keypairs = new Map<number, Keypair>([[0, kp]]);
		const derivationPaths = new Map<number, string | undefined>([[0, path]]);

		this.keyrings.set(name, {
			keypairs,
			derivationPaths,
			mnemonic: mnemonicPhrase,
			password,
		});

		return this.buildKeyring(this.getStored(name));
	}

	async load(name: string, password: string): Promise<Keyring> {
		const stored = this.getStored(name);
		this.checkPassword(stored, password);
		return this.buildKeyring(stored);
	}

	async list(): Promise<string[]> {
		return Array.from(this.keyrings.keys()).sort();
	}

	async exists(name: string): Promise<boolean> {
		return this.keyrings.has(name);
	}

	async getPublicKey(name: string): Promise<PublicKey> {
		const stored = this.getStored(name);
		const kp = stored.keypairs.get(0);
		if (!kp) throw new RialoError(RialoErrorType.WALLET, `Keyring ${name} has no keypair at index 0`);
		return kp.publicKey;
	}

	async listPublicKeys(): Promise<[string, DerivedKeypairInfo][]> {
		const results: [string, DerivedKeypairInfo][] = [];
		for (const [name, stored] of this.keyrings) {
			const kp = stored.keypairs.get(0);
			if (kp) {
				results.push([name, this.toInfo(0, kp, stored.derivationPaths.get(0))]);
			}
		}
		results.sort((a, b) => a[0].localeCompare(b[0]));
		return results;
	}

	async listKeypairs(keyringName: string): Promise<DerivedKeypairInfo[]> {
		const stored = this.getStored(keyringName);
		const indices = Array.from(stored.keypairs.keys()).sort((a, b) => a - b);
		return indices.map((idx) => {
			const kp = stored.keypairs.get(idx)!;
			return this.toInfo(idx, kp, stored.derivationPaths.get(idx));
		});
	}

	async deriveKeypair(
		keyringName: string,
		keypairIndex: number,
		password: string,
	): Promise<DerivedKeypairInfo> {
		validateKeypairIndex(keypairIndex);

		const stored = this.getStored(keyringName);
		this.checkPassword(stored, password);

		if (stored.keypairs.has(keypairIndex)) {
			throw new RialoError(
				RialoErrorType.WALLET,
				`Keypair with index ${keypairIndex} already exists`,
			);
		}

		let kp: Keypair;
		let derivationPath: string | undefined;

		if (stored.mnemonic) {
			const mnemonic = Mnemonic.fromPhrase(stored.mnemonic);
			kp = await mnemonic.toKeypair(keypairIndex);
			derivationPath = `${BASE_DERIVATION_PATH}${keypairIndex}'/0'`;
		} else {
			kp = Keypair.generate();
			derivationPath = undefined;
		}

		stored.keypairs.set(keypairIndex, kp);
		stored.derivationPaths.set(keypairIndex, derivationPath);

		return this.toInfo(keypairIndex, kp, derivationPath);
	}

	async importSecretKey(
		keyringName: string,
		secretKey: Uint8Array,
		derivationPath: string | undefined,
		password: string,
	): Promise<DerivedKeypairInfo> {
		if (secretKey.length !== 32) {
			throw new RialoError(
				RialoErrorType.INVALID_INPUT,
				`Invalid secret key length: expected 32 bytes, got ${secretKey.length}`,
			);
		}

		const stored = this.getStored(keyringName);
		this.checkPassword(stored, password);

		const kp = Keypair.fromSecretKey(secretKey);
		const nextIdx = this.nextIndex(stored);

		stored.keypairs.set(nextIdx, kp);
		stored.derivationPaths.set(nextIdx, derivationPath);

		return this.toInfo(nextIdx, kp, derivationPath);
	}

	async getKeypairsInfo(name: string): Promise<DerivedKeypairInfo[]> {
		return this.listKeypairs(name);
	}

	async getKeypairInfo(name: string, keypairIndex: number): Promise<DerivedKeypairInfo> {
		validateKeypairIndex(keypairIndex);
		const stored = this.getStored(name);
		const kp = stored.keypairs.get(keypairIndex);
		if (!kp) {
			throw new RialoError(
				RialoErrorType.WALLET,
				`Keypair ${keypairIndex} not found in keyring ${name}`,
			);
		}
		return this.toInfo(keypairIndex, kp, stored.derivationPaths.get(keypairIndex));
	}

	async nextKeypairIndex(name: string): Promise<number> {
		const stored = this.getStored(name);
		return this.nextIndex(stored);
	}
}
