import { SYSTEM_PROGRAM_ID } from "../../constants";
import { PublicKey } from "../../crypto";
import { BincodeWriter } from "../../serialization/bincode";
import type { Instruction } from "../types";

/**
 * System program instruction types.
 */
export enum SystemInstruction {
	CreateAccount = 0,
	Assign = 1,
	Transfer = 2,
	CreateAccountWithSeed = 3,
	AdvanceNonceAccount = 4,
	WithdrawNonceAccount = 5,
	InitializeNonceAccount = 6,
	AuthorizeNonceAccount = 7,
	Allocate = 8,
	AllocateWithSeed = 9,
	AssignWithSeed = 10,
	TransferWithSeed = 11,
}

/**
 * Create a transfer instruction.
 *
 * Transfers native tokens from one account to another.
 *
 * @param from - Source account (must be signer)
 * @param to - Destination account
 * @param amount - Amount to transfer in smallest denomination (kelvins)
 *
 * @example
 * ```typescript
 * const instruction = transferInstruction(fromPubkey, toPubkey, 1_000_000n);
 *
 * const tx = TransactionBuilder.create()
 *   .setPayer(fromPubkey)
 *   .addInstruction(instruction)
 *   .build();
 * ```
 */
export function transferInstruction(
	from: PublicKey,
	to: PublicKey,
	amount: bigint,
): Instruction {
	// Instruction data: bincode serialization format
	// - 4 bytes: variant index as u32 little-endian (2 for Transfer)
	// - 8 bytes: amount as u64 little-endian
	const writer = new BincodeWriter(12);
	writer.writeVariant(SystemInstruction.Transfer);
	writer.writeU64(amount);

	return {
		programId: PublicKey.fromString(SYSTEM_PROGRAM_ID),
		accounts: [
			{ pubkey: from, isSigner: true, isWritable: true },
			{ pubkey: to, isSigner: false, isWritable: true },
		],
		data: writer.toBytes(),
	};
}

/**
 * Create an account creation instruction.
 *
 * @param from - Funding account (must be signer)
 * @param newAccount - New account to create (must be signer)
 * @param kelvins - Initial balance for new account
 * @param space - Number of bytes to allocate for account data
 * @param owner - Program that will own the new account
 */
export function createAccount(
	from: PublicKey,
	newAccount: PublicKey,
	kelvins: bigint,
	space: bigint,
	owner: PublicKey,
): Instruction {
	// Instruction data: bincode serialization format
	// - 4 bytes: variant index as u32 little-endian (0 for CreateAccount)
	// - 8 bytes: kelvins as u64 little-endian
	// - 8 bytes: space as u64 little-endian
	// - 32 bytes: owner public key
	const writer = new BincodeWriter(52);
	writer.writeVariant(SystemInstruction.CreateAccount);
	writer.writeU64(kelvins);
	writer.writeU64(space);
	writer.writeBytes(owner.toBytes());

	return {
		programId: PublicKey.fromString(SYSTEM_PROGRAM_ID),
		accounts: [
			{ pubkey: from, isSigner: true, isWritable: true },
			{ pubkey: newAccount, isSigner: true, isWritable: true },
		],
		data: writer.toBytes(),
	};
}

/**
 * Create an allocate instruction.
 *
 * Allocates space for an account's data. The account must be owned by
 * the system program and must sign the transaction.
 *
 * @param account - Account to allocate space for (must be signer)
 * @param space - Number of bytes to allocate
 */
export function allocateInstruction(
	account: PublicKey,
	space: bigint,
): Instruction {
	// Instruction data: bincode serialization format
	// - 4 bytes: variant index as u32 little-endian (8 for Allocate)
	// - 8 bytes: space as u64 little-endian
	const writer = new BincodeWriter(12);
	writer.writeVariant(SystemInstruction.Allocate);
	writer.writeU64(space);

	return {
		programId: PublicKey.fromString(SYSTEM_PROGRAM_ID),
		accounts: [
			{ pubkey: account, isSigner: true, isWritable: true },
		],
		data: writer.toBytes(),
	};
}

/**
 * Create an assign instruction.
 *
 * Changes the owner of an account. The account must currently be owned
 * by the system program and must sign the transaction.
 *
 * @param account - Account to reassign (must be signer)
 * @param owner - New owner program
 */
export function assignInstruction(
	account: PublicKey,
	owner: PublicKey,
): Instruction {
	// Instruction data: bincode serialization format
	// - 4 bytes: variant index as u32 little-endian (1 for Assign)
	// - 32 bytes: owner public key
	const writer = new BincodeWriter(36);
	writer.writeVariant(SystemInstruction.Assign);
	writer.writeBytes(owner.toBytes());

	return {
		programId: PublicKey.fromString(SYSTEM_PROGRAM_ID),
		accounts: [
			{ pubkey: account, isSigner: true, isWritable: true },
		],
		data: writer.toBytes(),
	};
}
