import type { FrostAppState, WalletEntity } from "@rialo/frost-core";
import { useStore } from "@tanstack/react-store";
import { useFrostConfig } from "../context";

/**
 * Selector for the active wallet.
 * Defined at module level since it has no dependencies and never changes,
 * preventing unnecessary re-subscriptions in TanStack Store.
 */
const selectActiveWallet = (state: FrostAppState): WalletEntity | null => {
  if (!state.walletName) return null;
  return state.wallets.get(state.walletName) ?? null;
};

/**
 * Hook to get the currently active wallet.
 *
 * @returns Active wallet or null if not connected
 *
 * @example
 * ```tsx
 * function WalletInfo() {
 *   const wallet = useActiveWallet();
 *
 *   if (!wallet) return <div>No wallet connected</div>;
 *   return <div>Connected to: {wallet.name}</div>;
 * }
 * ```
 */
export function useActiveWallet(): WalletEntity | null {
  const config = useFrostConfig();
  return useStore(config.store, selectActiveWallet);
}
