import { Keyring as KeyringBase } from "../generated/keyring.js";
import type { DerivedKeypairInfo, PublicKey } from "../generated/types.js";
import { Keypair } from "../crypto/keypair.js";
import { Signature } from "../crypto/signature.js";
import { RialoError, RialoErrorType } from "../error.js";
import { validateKeypairIndex } from "./validation.js";

/**
 * Concrete keyring implementation backed by an in-memory map of derived keypairs.
 *
 * Keyrings are created via {@link InMemoryKeyringProvider}, not directly.
 * The active keypair defaults to index 0. Use {@link setActiveKeypair} to change it.
 * Secret material stays inside the keyring — callers interact via indices and public metadata.
 */
export class RialoKeyring extends KeyringBase {
	private readonly keypairs: Map<number, Keypair>;
	private readonly derivationPaths: Map<number, string | undefined>;
	private activeIndex: number;

	constructor(
		keypairs: Map<number, Keypair>,
		derivationPaths: Map<number, string | undefined>,
	) {
		super();
		this.keypairs = keypairs;
		this.derivationPaths = derivationPaths;
		this.activeIndex = 0;
	}

	/**
	 * Sets the active keypair index (facade operation, not in WIT contract).
	 *
	 * @param index - The keypair index to make active
	 * @throws {RialoError} If the index does not exist in this keyring
	 */
	setActiveKeypair(index: number): void {
		validateKeypairIndex(index);
		if (!this.keypairs.has(index)) {
			throw new RialoError(
				RialoErrorType.WALLET,
				`Keypair ${index} not found in keyring`,
			);
		}
		this.activeIndex = index;
	}

	private activeKeypair(): Keypair {
		const kp = this.keypairs.get(this.activeIndex);
		if (!kp) {
			throw new RialoError(RialoErrorType.WALLET, "Active keypair does not exist");
		}
		return kp;
	}

	sign(message: Uint8Array): Uint8Array {
		return this.activeKeypair().sign(message).toBytes();
	}

	verify(message: Uint8Array, sig: Uint8Array): boolean {
		return this.activeKeypair().verify(message, Signature.fromBytes(sig));
	}

	pubkeyString(): string {
		return this.activeKeypair().publicKey.toString();
	}

	pubkey(): PublicKey {
		return this.activeKeypair().publicKey;
	}

	getKeypairInfo(index: number): DerivedKeypairInfo | undefined {
		validateKeypairIndex(index);
		const kp = this.keypairs.get(index);
		if (!kp) return undefined;
		return {
			index,
			pubkey: kp.publicKey,
			pubkeyString: kp.publicKey.toString(),
			derivationPath: this.derivationPaths.get(index) ?? undefined,
		};
	}

	listKeypairs(): number[] {
		return Array.from(this.keypairs.keys()).sort((a, b) => a - b);
	}

	getKeypairsInfo(): DerivedKeypairInfo[] {
		return this.listKeypairs().map((index) => this.getKeypairInfo(index)!);
	}

	signWithKeypair(message: Uint8Array, index: number): Uint8Array {
		validateKeypairIndex(index);
		const kp = this.keypairs.get(index);
		if (!kp) {
			throw new RialoError(
				RialoErrorType.WALLET,
				`Keypair ${index} not found in keyring`,
			);
		}
		return kp.sign(message).toBytes();
	}

	/**
	 * Securely erases all secret key material from this keyring snapshot.
	 *
	 * Calls {@link Keypair.dispose} on every keypair, zeroing private key bytes.
	 * After disposal, signing and secret-key export will throw. Verification
	 * still works (uses only the public key). Does not affect provider-stored
	 * state or other snapshots.
	 */
	dispose(): void {
		for (const kp of this.keypairs.values()) {
			kp.dispose();
		}
	}
}
