import type { FrostAppState, RialoClientConfig } from "@rialo/frost-core";
import { useStore } from "@tanstack/react-store";
import { useCallback } from "react";
import { useFrostConfig } from "../context";

export interface UseSwitchChainOptions {
  onSuccess?: () => void;
  onError?: (error: Error) => void;
}

/**
 * Selector for chain ID.
 * Defined at module level since it has no dependencies and never changes.
 */
const selectChainId = (state: FrostAppState): string => state.chainId;

/**
 * Hook to switch to a different chain/network.
 *
 * @example
 * ```tsx
 * import { getDefaultRialoClientConfig } from '@rialo/ts-cdk';
 *
 * function NetworkSwitcher() {
 *   const switchChain = useSwitchChain();
 *
 *   return (
 *     <button
 *       onClick={() => switchChain(getDefaultRialoClientConfig('mainnet'))}
 *     >
 *       Switch to Mainnet
 *     </button>
 *   );
 * }
 * ```
 */
export function useSwitchChain(): (clientConfig: RialoClientConfig) => void {
  const config = useFrostConfig();

  const switchChain = useCallback(
    () =>
      (clientConfig: RialoClientConfig): void => {
        config.switchChain(clientConfig);
      },
    [config]
  );

  return switchChain;
}

/**
 * Hook to get the current chain ID.
 * Reactively updates when chain changes.
 *
 * The selector is stable (defined at module level) to prevent
 * unnecessary re-subscriptions.
 *
 * @example
 * ```tsx
 * function NetworkDisplay() {
 *   const chainId = useChainId();
 *   return <div>Connected to: {chainId}</div>;
 * }
 * ```
 */
export function useChainId(): string {
  const config = useFrostConfig();
  return useStore(config.store, selectChainId);
}
