/**
 * Account metadata table for deduplication and sorting.
 * Avoids: Complex account sorting logic scattered throughout builder
 */

import type { PublicKey } from "../crypto";
import type { AccountMeta, MessageHeader } from "./types";

/**
 * Internal account entry with aggregated metadata.
 */
interface AccountEntry {
	pubkey: PublicKey;
	isSigner: boolean;
	isWritable: boolean;
}

/**
 * Manages account deduplication and sorting for transaction messages.
 *
 * Accounts are sorted according to these rules:
 * 1. Signer + writable accounts first
 * 2. Then signer + readonly accounts
 * 3. Then non-signer + writable accounts
 * 4. Finally non-signer + readonly accounts
 * 5. Within each group, sort by public key bytes
 *
 * This matches Solana's account sorting rules for compatibility.
 */
export class AccountMetaTable {
	private readonly accounts: Map<string, AccountEntry> = new Map();
	private readonly accountOrder: string[] = [];
	private payerKey: string | null = null;

	/**
	 * Set the fee payer for this transaction.
	 * The fee payer is always pinned at index 0 in the sorted account list,
	 * regardless of lexicographic ordering. This matches Solana's invariant
	 * that account_keys[0] is always the fee payer.
	 */
	setFeePayer(pubkey: PublicKey): void {
		this.payerKey = pubkey.toString();
		this.add({ pubkey, isSigner: true, isWritable: true });
	}

	/**
	 * Add or update an account in the table.
	 * If account already exists, merges signer/writable flags (OR operation).
	 */
	add(meta: AccountMeta): void {
		const key = meta.pubkey.toString();

		if (this.accounts.has(key)) {
			// Merge with existing entry (OR flags)
			// biome-ignore lint/style/noNonNullAssertion: we know the key is in the map
			const existing = this.accounts.get(key)!;
			existing.isSigner ||= meta.isSigner;
			existing.isWritable ||= meta.isWritable;
		} else {
			// New entry
			this.accounts.set(key, {
				pubkey: meta.pubkey,
				isSigner: meta.isSigner,
				isWritable: meta.isWritable,
			});
			this.accountOrder.push(key);
		}
	}

	/**
	 * Add multiple accounts at once.
	 */
	addAll(metas: readonly AccountMeta[]): void {
		for (const meta of metas) {
			this.add(meta);
		}
	}

	/**
	 * Get the index of an account in the sorted order.
	 * Returns -1 if account not found.
	 */
	getIndex(pubkey: PublicKey): number {
		const sorted = this.getSortedAccounts();
		return sorted.findIndex((entry) => entry.pubkey.equals(pubkey));
	}

	/**
	 * Get sorted accounts according to transaction rules.
	 */
	getSortedAccounts(): readonly AccountEntry[] {
		// biome-ignore lint/style/noNonNullAssertion: we know the key is in the map
		const entries = this.accountOrder.map((key) => this.accounts.get(key)!);

		// Separate fee payer from the rest so it can be pinned at index 0.
		// This matches the Rust CDK and Solana's invariant: account_keys[0] == fee_payer.
		let payerEntry: AccountEntry | null = null;
		const rest: AccountEntry[] = [];
		for (const entry of entries) {
			if (this.payerKey !== null && entry.pubkey.toString() === this.payerKey) {
				payerEntry = entry;
			} else {
				rest.push(entry);
			}
		}

		rest.sort((a, b): number => {
			// Priority 1: Signer + writable
			const aPriority =
				a.isSigner && a.isWritable ? 0 : a.isSigner ? 1 : a.isWritable ? 2 : 3;
			const bPriority =
				b.isSigner && b.isWritable ? 0 : b.isSigner ? 1 : b.isWritable ? 2 : 3;

			if (aPriority !== bPriority) {
				return aPriority - bPriority;
			}

			// Priority 2: Sort by public key bytes
			const aBytes = a.pubkey.toBytes();
			const bBytes = b.pubkey.toBytes();

			for (let i = 0; i < 32; i++) {
				if (aBytes[i] !== bBytes[i]) {
					return aBytes[i] - bBytes[i];
				}
			}

			return 0;
		});

		// Pin fee payer at index 0
		if (payerEntry !== null) {
			return [payerEntry, ...rest];
		}
		return rest;
	}

	/**
	 * Get the message header based on sorted accounts.
	 */
	getHeader(): MessageHeader {
		const sorted = this.getSortedAccounts();

		let numRequiredSignatures = 0;
		let numReadonlySignedAccounts = 0;
		let numReadonlyUnsignedAccounts = 0;

		for (const entry of sorted) {
			if (entry.isSigner) {
				numRequiredSignatures++;
				if (!entry.isWritable) {
					numReadonlySignedAccounts++;
				}
			} else if (!entry.isWritable) {
				numReadonlyUnsignedAccounts++;
			}
		}

		return {
			numRequiredSignatures,
			numReadonlySignedAccounts,
			numReadonlyUnsignedAccounts,
		};
	}

	/**
	 * Get sorted public keys.
	 */
	getPublicKeys(): readonly PublicKey[] {
		return this.getSortedAccounts().map((entry) => entry.pubkey);
	}

	/**
	 * Get number of accounts in table.
	 */
	size(): number {
		return this.accounts.size;
	}
}
