/**
 * Error codes for program deployment operations.
 */
export enum DeploymentErrorCode {
	// Validation errors
	EMPTY_PROGRAM_DATA = "EMPTY_PROGRAM_DATA",
	INVALID_CHUNK_SIZE = "INVALID_CHUNK_SIZE",

	// Deployment errors
	OWNER_MISMATCH = "OWNER_MISMATCH",
	TRANSACTION_FAILED = "TRANSACTION_FAILED",
	TRANSACTION_TIMEOUT = "TRANSACTION_TIMEOUT",
	RPC_ERROR = "RPC_ERROR",
	BUFFER_NOT_READY = "BUFFER_NOT_READY",
}

/**
 * Error class for program deployment operations with structured error information.
 */
export class DeploymentError extends Error {
	constructor(
		public readonly code: DeploymentErrorCode,
		message: string,
		public readonly details?: Record<string, unknown>,
	) {
		super(message);
		this.name = "DeploymentError";
	}

	static emptyProgramData(): DeploymentError {
		return new DeploymentError(
			DeploymentErrorCode.EMPTY_PROGRAM_DATA,
			"Program data must not be empty.",
		);
	}

	static invalidChunkSize(chunkSize: number): DeploymentError {
		return new DeploymentError(
			DeploymentErrorCode.INVALID_CHUNK_SIZE,
			`chunkSize must be greater than 0, got ${chunkSize}.`,
			{ chunkSize },
		);
	}

	static ownerMismatch(owner: string): DeploymentError {
		return new DeploymentError(
			DeploymentErrorCode.OWNER_MISMATCH,
			`Existing account is not owned by RISC-V Loader (owner: ${owner}).`,
			{ owner },
		);
	}

	static transactionFailed(err: string, details?: Record<string, unknown>): DeploymentError {
		return new DeploymentError(
			DeploymentErrorCode.TRANSACTION_FAILED,
			`Transaction failed: ${err}`,
			details,
		);
	}

	static transactionTimeout(message: string, details?: Record<string, unknown>): DeploymentError {
		return new DeploymentError(
			DeploymentErrorCode.TRANSACTION_TIMEOUT,
			`Transaction confirmation timed out: ${message}`,
			details,
		);
	}

	static rpcError(message: string, details?: Record<string, unknown>): DeploymentError {
		return new DeploymentError(
			DeploymentErrorCode.RPC_ERROR,
			`RPC error during deployment: ${message}`,
			details,
		);
	}

	static bufferNotReady(maxRetries: number): DeploymentError {
		return new DeploymentError(
			DeploymentErrorCode.BUFFER_NOT_READY,
			`Buffer account not ready after ${maxRetries} attempts.`,
			{ maxRetries },
		);
	}

	toJSON(): {
		code: DeploymentErrorCode;
		message: string;
		details?: Record<string, unknown>;
	} {
		return {
			code: this.code,
			message: this.message,
			details: this.details,
		};
	}
}
