import type { ConnectionStatus, FrostAppState } from "@rialo/frost-core";
import { useStore } from "@tanstack/react-store";
import { useFrostConfig } from "../context";

/**
 * Selector for connection status.
 * Defined at module level since it has no dependencies and never changes.
 */
const selectStatus = (state: FrostAppState): ConnectionStatus => state.status;

/**
 * Selector for connected state.
 * Defined at module level since it has no dependencies and never changes.
 */
const selectIsConnected = (state: FrostAppState): boolean => state.status === "connected";

/**
 * Hook to get the current connection status.
 *
 * @returns Connection status: "disconnected" | "connecting" | "connected" | "reconnecting"
 *
 * @example
 * ```tsx
 * function StatusIndicator() {
 *   const status = useConnectionStatus();
 *   return <div>Status: {status}</div>;
 * }
 * ```
 */
export function useConnectionStatus(): ConnectionStatus {
  const config = useFrostConfig();
  return useStore(config.store, selectStatus);
}

/**
 * Hook to check if currently connected.
 *
 * @returns True if a wallet is connected
 *
 * @example
 * ```tsx
 * function App() {
 *   const isConnected = useIsConnected();
 *   return isConnected ? <Dashboard /> : <ConnectPrompt />;
 * }
 * ```
 */
export function useIsConnected(): boolean {
  const config = useFrostConfig();
  return useStore(config.store, selectIsConnected);
}
