import { ristretto255 } from "@noble/curves/ed25519.js";
import { bytesToNumberLE } from "@noble/curves/utils.js";
import { chacha20poly1305 } from "@noble/ciphers/chacha";
import { hkdf } from "@noble/hashes/hkdf";
import { sha256 } from "@noble/hashes/sha2";
import { randomBytes } from "@noble/hashes/utils";

import type { SecretSharingPubkey } from "../generated/types.js";
import { EncryptionError } from "./errors.js";
import { RexValue } from "./rex-value.js";

// Ristretto255 group order l = 2^252 + 27742317777372353535851937790883648493
const RISTRETTO255_ORDER = BigInt(
	"0x1000000000000000000000000000000014def9dea2f79cd65812631a5cf5d3ed",
);

// Internal constants — must match Rust secret_encryption.rs exactly
const DKG_KDF_SALT = /* @__PURE__ */ new TextEncoder().encode(
	"RIALO_DKG_THRESHOLD_V1",
);
const DKG_ACL_AAD_DOMAIN = /* @__PURE__ */ new TextEncoder().encode(
	"RIALO_DKG_ACL_V1", // exactly 16 bytes
);

const DKG_PAYLOAD_VERSION = 0x02;
const MAX_SECRET_LENGTH = 64 * 1024;
const RISTRETTO_POINT_BYTES = 32;
const ED25519_PUBKEY_BYTES = 32;
const CHACHA20_NONCE_BYTES = 12;

function buildAad(creatorPubkey: Uint8Array): Uint8Array {
	const aad = new Uint8Array(DKG_ACL_AAD_DOMAIN.length + creatorPubkey.length);
	aad.set(DKG_ACL_AAD_DOMAIN, 0);
	aad.set(creatorPubkey, DKG_ACL_AAD_DOMAIN.length);
	return aad;
}

function buildKdfInfo(
	epoch: bigint,
	headerU: Uint8Array,
	aad: Uint8Array,
): Uint8Array {
	const info = new Uint8Array(8 + RISTRETTO_POINT_BYTES + aad.length);
	new DataView(info.buffer).setBigUint64(0, epoch, true);
	info.set(headerU, 8);
	info.set(aad, 8 + RISTRETTO_POINT_BYTES);
	return info;
}

// Manual Borsh encoding of DkgEncryptedPayload (matches Rust struct field order)
//   epoch:           u64  (8 bytes LE)
//   ciphertext_u:    [u8; 32]
//   ciphertext_body: Vec<u8>  (u32 LE length prefix + bytes)
//   ciphertext_nonce:[u8; 12]
//   ciphertext_aad:  Vec<u8>  (u32 LE length prefix + bytes)
function encodeDkgPayload(
	epoch: bigint,
	ciphertextU: Uint8Array,
	ciphertextBody: Uint8Array,
	ciphertextNonce: Uint8Array,
	ciphertextAad: Uint8Array,
): Uint8Array {
	const size =
		8 +
		RISTRETTO_POINT_BYTES +
		4 + ciphertextBody.length +
		CHACHA20_NONCE_BYTES +
		4 + ciphertextAad.length;
	const buf = new Uint8Array(size);
	const view = new DataView(buf.buffer);
	let off = 0;
	view.setBigUint64(off, epoch, true);
	off += 8;
	buf.set(ciphertextU, off);
	off += RISTRETTO_POINT_BYTES;
	view.setUint32(off, ciphertextBody.length, true);
	off += 4;
	buf.set(ciphertextBody, off);
	off += ciphertextBody.length;
	buf.set(ciphertextNonce, off);
	off += CHACHA20_NONCE_BYTES;
	view.setUint32(off, ciphertextAad.length, true);
	off += 4;
	buf.set(ciphertextAad, off);
	return buf;
}

/**
 * Encrypt raw bytes using the DKG threshold public key.
 *
 * Low-level variant for callers that supply an explicit epoch and hex-encoded
 * threshold public key rather than a full `SecretSharingPubkey` struct.
 *
 * Uses ElGamal-style ECIES over Ristretto255 with HKDF-SHA256 key derivation
 * and ChaCha20-Poly1305 AEAD. The output format is:
 * `[0x02] || borsh(DkgEncryptedPayload)` — matching the Rust CDK exactly.
 *
 * @param plaintext - Raw bytes to encrypt (non-empty, max 64 KB)
 * @param creatorPubkey - Ed25519 public key (32 bytes) bound into the AAD
 * @param epoch - DKG epoch identifying the joint public key
 * @param thresholdPubkeyHex - Hex-encoded compressed Ristretto255 joint public key (32 bytes)
 * @throws {EncryptionError} On invalid inputs or encryption failure
 */
export function encryptSecretBytesWithEpoch(
	plaintext: Uint8Array,
	creatorPubkey: Uint8Array,
	epoch: bigint,
	thresholdPubkeyHex: string,
): Uint8Array {
	if (plaintext.length === 0) {
		throw EncryptionError.invalidInput("Secret cannot be empty");
	}
	if (plaintext.length > MAX_SECRET_LENGTH) {
		throw EncryptionError.invalidInput(
			`Secret exceeds maximum length of ${MAX_SECRET_LENGTH} bytes (got ${plaintext.length} bytes)`,
		);
	}
	if (creatorPubkey.length !== ED25519_PUBKEY_BYTES) {
		throw EncryptionError.invalidInput(
			`Creator public key must be ${ED25519_PUBKEY_BYTES} bytes, got ${creatorPubkey.length}`,
		);
	}
	if (epoch < 0n || epoch > 0xffffffffffffffffn) {
		throw EncryptionError.invalidInput(
			`Epoch must be a valid u64 (0 to 2^64-1), got ${epoch}`,
		);
	}

	let jointPubKey: ReturnType<typeof ristretto255.Point.fromHex>;
	try {
		jointPubKey = ristretto255.Point.fromHex(thresholdPubkeyHex);
	} catch (e) {
		throw EncryptionError.invalidThresholdKey(
			e instanceof Error ? e : new Error(String(e)),
		);
	}

	// AAD: b"RIALO_DKG_ACL_V1" (16 bytes) || creatorPubkey (32 bytes)
	const aad = buildAad(creatorPubkey);

	// Ephemeral scalar r from 64 random bytes, matching Scalar::from_bytes_mod_order_wide
	const r = bytesToNumberLE(randomBytes(64)) % RISTRETTO255_ORDER;

	// U = r·G  (ElGamal header point, compressed to 32 bytes)
	const headerUBytes = ristretto255.Point.BASE.multiply(r).toBytes();

	// Z = r·Y  (shared secret point, compressed to 32 bytes)
	const combinedZBytes = jointPubKey.multiply(r).toBytes();

	// Session key via HKDF-SHA256(salt, ikm=Z, info=epoch||U||aad, len=32)
	const sessionKey = hkdf(
		sha256,
		combinedZBytes,
		DKG_KDF_SALT,
		buildKdfInfo(epoch, headerUBytes, aad),
		32,
	);

	const nonce = randomBytes(CHACHA20_NONCE_BYTES);
	const ciphertextBody = chacha20poly1305(sessionKey, nonce, aad).encrypt(
		plaintext,
	);

	const payload = encodeDkgPayload(epoch, headerUBytes, ciphertextBody, nonce, aad);
	const result = new Uint8Array(1 + payload.length);
	result[0] = DKG_PAYLOAD_VERSION;
	result.set(payload, 1);
	return result;
}

/**
 * Encrypt raw bytes using the active DKG threshold public key.
 *
 * Accepts a `SecretSharingPubkey` (as returned by `getSecretSharingPubkey()`)
 * and produces a versioned `DkgEncryptedPayload` that the network can
 * threshold-decrypt during REX execution.
 *
 * @param plaintext - Raw bytes to encrypt (non-empty, max 64 KB)
 * @param creatorPubkey - Ed25519 public key (32 bytes) bound into the AAD
 * @param secretSharingPubkey - Active threshold key metadata from RPC
 * @throws {EncryptionError} On invalid inputs or encryption failure
 *
 * @example
 * ```typescript
 * const { publicKey, epoch } = await client.getSecretSharingPubkey();
 * const payload = encryptSecretBytes(
 *   new TextEncoder().encode("my-api-key"),
 *   keypair.publicKey.toBytes(),
 *   { publicKey, epoch },
 * );
 * const rexValue = RexValue.encrypted(payload);
 * ```
 */
export function encryptSecretBytes(
	plaintext: Uint8Array,
	creatorPubkey: Uint8Array,
	secretSharingPubkey: SecretSharingPubkey,
): Uint8Array {
	return encryptSecretBytesWithEpoch(
		plaintext,
		creatorPubkey,
		secretSharingPubkey.epoch,
		secretSharingPubkey.publicKey,
	);
}

/**
 * Encrypt a UTF-8 string using the active DKG threshold public key.
 *
 * Convenience wrapper around `encryptSecretBytes` for string secrets.
 *
 * @param secret - The plaintext string to encrypt (non-empty, max 64 KB)
 * @param creatorPubkey - Ed25519 public key (32 bytes)
 * @param secretSharingPubkey - Active threshold key metadata from RPC
 * @throws {EncryptionError} On invalid inputs or encryption failure
 *
 * @example
 * ```typescript
 * const payload = encryptSecret(
 *   "Bearer sk-1234567890abcdef",
 *   keypair.publicKey.toBytes(),
 *   await client.getSecretSharingPubkey(),
 * );
 * ```
 */
export function encryptSecret(
	secret: string,
	creatorPubkey: Uint8Array,
	secretSharingPubkey: SecretSharingPubkey,
): Uint8Array {
	return encryptSecretBytes(
		new TextEncoder().encode(secret),
		creatorPubkey,
		secretSharingPubkey,
	);
}

/**
 * Encrypt raw bytes for REX and wrap the result in a `RexValue`.
 *
 * Combines `encryptSecretBytes` with `RexValue.encrypted`. The resulting
 * `RexValue` can be serialized to Borsh and included in transactions.
 *
 * @param plaintext - Raw bytes to encrypt
 * @param creatorPubkey - Ed25519 public key (32 bytes)
 * @param secretSharingPubkey - Active threshold key metadata from RPC
 * @throws {EncryptionError} On invalid inputs or encryption failure
 *
 * @example
 * ```typescript
 * const rexValue = encryptForRex(
 *   new TextEncoder().encode("my secret"),
 *   keypair.publicKey.toBytes(),
 *   await client.getSecretSharingPubkey(),
 * );
 * const borshBytes = rexValue.toBorsh();
 * ```
 */
export function encryptForRex(
	plaintext: Uint8Array,
	creatorPubkey: Uint8Array,
	secretSharingPubkey: SecretSharingPubkey,
): RexValue {
	return RexValue.encrypted(
		encryptSecretBytes(plaintext, creatorPubkey, secretSharingPubkey),
	);
}
